/**
 * Mesh Policy — TypeScript mirror of nine zero-sorry Lean modules:
 *
 *   - ForkRaceFoldTheorems.AntiDomainOverlay
 *   - ForkRaceFoldTheorems.DiscreteSamplingDuel
 *   - ForkRaceFoldTheorems.ZenonicBarrier
 *   - ForkRaceFoldTheorems.RationalCutMiscalibration
 *   - ForkRaceFoldTheorems.PortAuthenticatedMesh
 *   - ForkRaceFoldTheorems.CompetingOverlayResolution
 *   - ForkRaceFoldTheorems.IceAntiIceCatalog
 *   - ForkRaceFoldTheorems.HoneyPit
 *   - ForkRaceFoldTheorems.LinkedMeshComposition
 *
 * Canonical SSOT for mesh-policy primitives: regions and anti-domain
 * overlays, discrete clock sampling duels, Zenonic contraction gaps,
 * Fibonacci-resonant rational cuts, port-authenticated meshes,
 * competing-overlay inclusion-exclusion resolution, the three
 * structurally distinct ICE / anti-ICE bypass surfaces, honey-pit
 * shared-drain contraction sinks, and horizontal linked-mesh
 * composition.
 *
 * Semantics are Nat-valued in the Lean source; this module uses
 * `number` under non-negative integer discipline. Negative inputs are
 * undefined behaviour outside of factory validators; `Math.max(0, ...)`
 * clamps where the Lean source truncates via `Nat.sub`.
 */

// The canonical ternary verdict (accept / abstain / decline), shared with the
// rest of the distributed-inference grid. Adopted ADDITIVELY at the mesh-policy
// decision sites: each ad-hoc admit/accept/select boolean keeps its lossy
// `=== true` collapse (`isAccept(verdict)`) while gaining a faithful `verdict`
// that can hold the neutral middle a bool cannot — deferral / deliberate
// non-adoption / unscheduled-but-not-disqualified. Pure module (no node deps),
// safe for the node-free production surface check. Lean: Gnosis.TritonCanonical.
import {
  Verdict,
  isAccept,
  isReject,
  isDefer,
} from '../../bitwise/src/triton-verdict.js';

// ─── Part I: Regions and Overlays ─────────────────────────────────────

/** A spatial region: a discrete set of target points of positive size.
 *  Mirrors `AntiDomainOverlay.Region` and `CompetingOverlayResolution.Region`. */
export interface Region {
  readonly size: number;
}

/** An overlay: a sub-enclosure whose `size` measures its support within
 *  the enclosing region. Mirrors `AntiDomainOverlay.Overlay`. */
export interface Overlay {
  readonly size: number;
}

/** Construct a Region with positive-size precondition.
 *  Mirrors the Lean `hPositive : 0 < size` constraint. */
export function createRegion(size: number): Region {
  if (!Number.isInteger(size) || size <= 0) {
    throw new RangeError(`Region size must be a positive integer, got ${size}`);
  }
  return { size };
}

/** Construct an Overlay with non-negative-size precondition. */
export function createOverlay(size: number): Overlay {
  if (!Number.isInteger(size) || size < 0) {
    throw new RangeError(
      `Overlay size must be a non-negative integer, got ${size}`
    );
  }
  return { size };
}

/** Mirror of `enclosedHitCount` (Lean) — every point in the region is
 *  guaranteed to be hit. */
export function enclosedHitCount(r: Region): number {
  return r.size;
}

/** Mirror of `netHitCount` / `overlayCancelsLocally` (Lean) — net hits
 *  after applying an overlay is `r.size - ov.size` with Nat-truncation. */
export function netHitCount(r: Region, ov: Overlay): number {
  return Math.max(0, r.size - ov.size);
}

/** Mirror of `stackOverlays` / `orthogonalOverlaysStackAdditively` (Lean) —
 *  two overlays with additive-disjoint supports compose by summing sizes. */
export function stackOverlays(ov1: Overlay, ov2: Overlay): Overlay {
  return { size: ov1.size + ov2.size };
}

// ─── Part II: Clocks and Sampling Duels ───────────────────────────────

/** A discrete clock: a positive integer tick rate.
 *  Mirrors `DiscreteSamplingDuel.Clock`. */
export interface Clock {
  readonly rate: number;
}

/** Construct a Clock with positive-rate precondition.
 *  Mirrors Lean `hPositive : 0 < rate`. */
export function createClock(rate: number): Clock {
  if (!Number.isInteger(rate) || rate <= 0) {
    throw new RangeError(`Clock rate must be a positive integer, got ${rate}`);
  }
  return { rate };
}

/** Mirror of `tickCount` (Lean) — ticks produced by clock `c` over
 *  sampling horizon `H`. */
export function tickCount(c: Clock, H: number): number {
  return Math.max(0, H) * c.rate;
}

/** Mirror of `frameDeficitFormula` (Lean) — `H * (fA - fB)` when
 *  `fB <= fA`. Clamped to zero when `fB > fA`. */
export function frameDeficit(horizon: number, fA: number, fB: number): number {
  const H = Math.max(0, horizon);
  return H * Math.max(0, fA - fB);
}

/** Mirror of `resonanceAlignsExactly` (Lean) — detect whether `fA` is an
 *  integer multiple `k * fB` for some `k >= 1`, given `0 < fB`. */
export function isResonant(fA: number, fB: number): boolean {
  if (!Number.isInteger(fA) || !Number.isInteger(fB)) return false;
  if (fB <= 0 || fA < fB) return false;
  return fA % fB === 0;
}

// ─── Part III: Zenonic Barrier ────────────────────────────────────────

/** A Zenonic gap: numerator over a positive denominator. The effective
 *  gap is `num / denom`. Mirrors `ZenonicBarrier.Gap`. */
export interface Gap {
  readonly num: number;
  readonly denom: number;
}

/** Construct a Gap with positive-denominator precondition.
 *  Mirrors Lean `hDenomPositive : 0 < denom`. */
export function createGap(num: number, denom: number): Gap {
  if (!Number.isInteger(num) || num < 0) {
    throw new RangeError(
      `Gap numerator must be a non-negative integer, got ${num}`
    );
  }
  if (!Number.isInteger(denom) || denom <= 0) {
    throw new RangeError(
      `Gap denominator must be a positive integer, got ${denom}`
    );
  }
  return { num, denom };
}

/** Mirror of `contractStep` / `denominatorDoublesPerStep` /
 *  `numeratorPreservedByStep` (Lean) — double the denominator, preserve
 *  the numerator. Halves the effective gap. */
export function contractStep(g: Gap): Gap {
  return { num: g.num, denom: 2 * g.denom };
}

/** Mirror of `iterate` (Lean) — apply `contractStep` `n` times. */
export function iterate(n: number, g: Gap): Gap {
  let current: Gap = g;
  const steps = Math.max(0, Math.floor(n));
  for (let i = 0; i < steps; i++) {
    current = contractStep(current);
  }
  return current;
}

/** Mirror of `barrierNeverReachedInFiniteSteps` (Lean) — an iterated gap
 *  with positive initial numerator never lands (`num > 0` always). The
 *  predicate holds when the current gap has reached numerator zero. */
export function hasLanded(g: Gap): boolean {
  return g.num === 0;
}

// ─── Part IV: Rational Cuts ───────────────────────────────────────────

/** Mirror of `fib` (Lean) — Fibonacci sequence with `fib(0) = 0`,
 *  `fib(1) = 1`, `fib(n+2) = fib(n) + fib(n+1)`. Memoized locally to
 *  avoid exponential recursion. */
const _fibCache: number[] = [0, 1];
/**
 * Handles the gnosis fib workflow.
 */
export function fib(n: number): number {
  if (!Number.isInteger(n) || n < 0) {
    throw new RangeError(`fib index must be a non-negative integer, got ${n}`);
  }
  while (_fibCache.length <= n) {
    const k = _fibCache.length;
    const prev = _fibCache[k - 2];
    const curr = _fibCache[k - 1];
    if (prev === undefined || curr === undefined) {
      // Unreachable by construction: cache is seeded with two entries.
      throw new Error(`fib cache corrupted at index ${k}`);
    }
    _fibCache.push(prev + curr);
  }
  const value = _fibCache[n];
  if (value === undefined) {
    throw new Error(`fib cache miss at index ${n}`);
  }
  return value;
}

/** Mirror of `isFibonacciResonantCut` (Lean) — a cut `(p, q)` is
 *  Fibonacci-resonant iff `(p, q) = (fib k, fib (k+1))` for some `k`.
 *
 *  Because `fib` is strictly increasing for `k >= 1`, this is decidable
 *  by a finite search bounded by the first index at which `fib k > p`.
 *  Mirrors `seven_three_not_resonant` / `three_seven_not_resonant`. */
export function isFibonacciResonantCut(p: number, q: number): boolean {
  if (!Number.isInteger(p) || !Number.isInteger(q) || p < 0 || q < 0) {
    return false;
  }
  // Special case: (fib 0, fib 1) = (0, 1).
  if (p === 0 && q === 1) return true;
  // Search k up to the first index with fib(k) > p.
  for (let k = 0; k < 512; k++) {
    const fk = fib(k);
    if (fk > p) return false;
    if (fk === p && fib(k + 1) === q) return true;
  }
  return false;
}

// ─── Part V: Port-Authenticated Mesh ──────────────────────────────────

/** A port-authenticated mesh: positive-size region with a whitelisted
 *  `portCount` subset. All non-port cells are default-deny.
 *  Mirrors `PortAuthenticatedMesh.Mesh`. */
export interface Mesh {
  readonly size: number;
  readonly portCount: number;
}

/** A port overlay: cancels hits on its support within the port subset.
 *  Mirrors `PortAuthenticatedMesh.PortOverlay`. */
export interface PortOverlay {
  readonly size: number;
}

/** Construct a Mesh with Lean-parity preconditions:
 *  `0 < size` (hPositive) and `portCount <= size` (hPortCountLe).
 *  This is the analogue of the Lean structure's proof obligations. */
export function createMesh(size: number, portCount: number): Mesh {
  if (!Number.isInteger(size) || size <= 0) {
    throw new RangeError(`Mesh size must be a positive integer, got ${size}`);
  }
  if (!Number.isInteger(portCount) || portCount < 0) {
    throw new RangeError(
      `Mesh portCount must be a non-negative integer, got ${portCount}`
    );
  }
  if (portCount > size) {
    throw new RangeError(`Mesh portCount ${portCount} exceeds size ${size}`);
  }
  return { size, portCount };
}

/** Construct a PortOverlay with non-negative-size precondition. */
export function createPortOverlay(size: number): PortOverlay {
  if (!Number.isInteger(size) || size < 0) {
    throw new RangeError(
      `PortOverlay size must be a non-negative integer, got ${size}`
    );
  }
  return { size };
}

/** Mirror of `netHitCount` (Lean, PortAuthenticatedMesh) — default-deny
 *  outside ports yields `m.portCount`. */
export function meshNetHitCount(m: Mesh): number {
  return m.portCount;
}

/** Mirror of `netHitCountWithOverlay` / `portOverlayCancelsWithinPorts`
 *  (Lean) — `m.portCount - ov.size` with Nat-truncation. */
export function meshNetHitCountWithOverlay(m: Mesh, ov: PortOverlay): number {
  return Math.max(0, m.portCount - ov.size);
}

/** Mirror of `netHitCountAuthenticated` / `authenticationRestrictsPorts`
 *  (Lean) — the authenticated sub-whitelist count is passed through
 *  directly; precondition `authenticatedCount <= m.portCount`. */
export function meshNetHitCountAuthenticated(
  m: Mesh,
  authenticatedCount: number
): number {
  return Math.max(0, Math.min(authenticatedCount, m.portCount));
}

// ─── Part VI: Competing Overlay Resolution ────────────────────────────

/** Two overlays competing on the same region with shared-support
 *  overlap. Mirrors the parameter tuple of
 *  `CompetingOverlayResolution.totalCancellation`.
 *
 *  The raw interface is preserved for backward compatibility. Prefer
 *  `createCompetingOverlays` to enforce the Lean precondition
 *  `overlap ≤ min ov1Size ov2Size`. */
export interface CompetingOverlays {
  readonly regionSize: number;
  readonly ov1Size: number;
  readonly ov2Size: number;
  readonly overlap: number;
}

/** Construct a `CompetingOverlays` with Lean-parity preconditions on
 *  the inclusion-exclusion triple. Mirrors the precondition
 *  `overlap ≤ min ov1Size ov2Size` required by
 *  `CompetingOverlayResolution.totalCancellation`.
 *
 *  Throws `RangeError` if:
 *    - any argument is not a non-negative integer;
 *    - `regionSize < 1`;
 *    - `ov1Size > regionSize` or `ov2Size > regionSize` (overlays
 *      cannot be larger than their enclosing region);
 *    - `overlap > ov1Size` or `overlap > ov2Size` (shared support
 *      cannot exceed either overlay). */
export function createCompetingOverlays(
  regionSize: number,
  ov1Size: number,
  ov2Size: number,
  overlap: number
): CompetingOverlays {
  const args: ReadonlyArray<readonly [string, number]> = [
    ['regionSize', regionSize],
    ['ov1Size', ov1Size],
    ['ov2Size', ov2Size],
    ['overlap', overlap],
  ];
  for (const [name, value] of args) {
    if (!Number.isInteger(value) || value < 0) {
      throw new RangeError(
        `${name} must be a non-negative integer, got ${value}`
      );
    }
  }
  if (regionSize < 1) {
    throw new RangeError(
      `regionSize must be a positive integer, got ${regionSize}`
    );
  }
  if (ov1Size > regionSize) {
    throw new RangeError(`ov1Size ${ov1Size} exceeds regionSize ${regionSize}`);
  }
  if (ov2Size > regionSize) {
    throw new RangeError(`ov2Size ${ov2Size} exceeds regionSize ${regionSize}`);
  }
  if (overlap > ov1Size) {
    throw new RangeError(
      `overlap ${overlap} exceeds ov1Size ${ov1Size} ` +
        `(Lean precondition: overlap ≤ min ov1Size ov2Size)`
    );
  }
  if (overlap > ov2Size) {
    throw new RangeError(
      `overlap ${overlap} exceeds ov2Size ${ov2Size} ` +
        `(Lean precondition: overlap ≤ min ov1Size ov2Size)`
    );
  }
  return { regionSize, ov1Size, ov2Size, overlap };
}

/** Mirror of `totalCancellation` / `disjointIsAdditive` /
 *  `fullContainmentCollapsesToLarger` / `bothFullCoverFullyCancels`
 *  (Lean) — inclusion-exclusion measure `ov1 + ov2 - overlap`.
 *
 *  Recommended construction: `createCompetingOverlays` enforces the
 *  Lean precondition `overlap ≤ min ov1Size ov2Size`. */
export function totalCancellation(c: CompetingOverlays): number {
  return Math.max(0, c.ov1Size + c.ov2Size - c.overlap);
}

/** Mirror of `netHitsAfterCompeting` / `mutualCancellationLowerBound`
 *  (Lean) — `r.size - (ov1 + ov2 - overlap)` with Nat-truncation.
 *  Symmetric in `ov1Size` / `ov2Size` (`deployOrderIrrelevant`).
 *
 *  Recommended construction: `createCompetingOverlays` enforces the
 *  Lean precondition `overlap ≤ min ov1Size ov2Size`. */
export function netHitsAfterCompeting(c: CompetingOverlays): number {
  return Math.max(0, c.regionSize - totalCancellation(c));
}

// ─── Part VII: ICE / Anti-ICE Catalog ─────────────────────────────────

/** Overlay-hole bypass witness: attacker reclaims on an
 *  additive-disjoint support. Mirrors `overlayHoleBypass` (Lean). */
export interface OverlayHoleBypass {
  readonly iceSize: number;
  readonly attackerSize: number;
  readonly regionSize: number;
  readonly reclaimedHits: number;
}

/** Clock-rate side-channel witness: attacker's frame deficit over
 *  horizon `H` with strictly faster tick rate. Mirrors
 *  `clockRateSideChannel` / `clockRateSideChannelUnbounded` (Lean). */
export interface ClockSideChannelBypass {
  readonly defenderRate: number;
  readonly attackerRate: number;
  readonly horizon: number;
  readonly frameDeficit: number;
  readonly strictlyPositive: boolean;
}

/** Zenonic-approach bypass witness: numerator-preserving contraction
 *  over `k` iterations. Mirrors `zenonicApproachBypass` /
 *  `zenonicApproachNumeratorFixed` (Lean). */
export interface ZenonicApproachBypass {
  readonly initialGap: Gap;
  readonly iterations: number;
  readonly finalGap: Gap;
  readonly hasLanded: boolean;
}

/** Mirror of `overlayHoleBypass` (Lean) — on an additive-disjoint
 *  support (`iceOv.size + attackerOv.size <= r.size`), the attacker's
 *  reclaimed hit count on its own support equals `attackerOv.size`,
 *  independently of `iceOv.size`. */
export function overlayHoleBypass(
  iceOv: Overlay,
  attackerOv: Overlay,
  regionSize: number
): OverlayHoleBypass {
  const disjointFits = iceOv.size + attackerOv.size <= regionSize;
  return {
    iceSize: iceOv.size,
    attackerSize: attackerOv.size,
    regionSize,
    reclaimedHits: disjointFits ? attackerOv.size : 0,
  };
}

/** Mirror of `clockRateSideChannel` (Lean) — with a strictly faster
 *  attacker clock over a positive horizon, the frame deficit is
 *  `H * (fA - fD)` and is strictly positive. */
export function clockSideChannelBypass(
  defenderClock: Clock,
  attackerClock: Clock,
  horizon: number
): ClockSideChannelBypass {
  const H = Math.max(0, horizon);
  const deficit = frameDeficit(H, attackerClock.rate, defenderClock.rate);
  return {
    defenderRate: defenderClock.rate,
    attackerRate: attackerClock.rate,
    horizon: H,
    frameDeficit: deficit,
    strictlyPositive:
      H > 0 && attackerClock.rate > defenderClock.rate && deficit > 0,
  };
}

/** Mirror of `zenonicApproachBypass` (Lean) — with a positive initial
 *  approach gap, for every finite `k` the iterated gap retains a
 *  positive numerator. The `hasLanded` flag witnesses whether the
 *  barrier was reached (Lean: always false for positive initial num). */
export function zenonicApproachBypass(
  initialGap: Gap,
  iterations: number
): ZenonicApproachBypass {
  const final = iterate(iterations, initialGap);
  return {
    initialGap,
    iterations: Math.max(0, Math.floor(iterations)),
    finalGap: final,
    hasLanded: hasLanded(final),
  };
}

// ─── Part VIII: Honey Pit (Shared-Drain Contraction Sink) ─────────────

/** A honey pit: a shared-drain contraction sink that inverts the
 *  attacker/defender cost asymmetry. `capacity` bounds simultaneous
 *  trapped connections, `inhabitants` tracks the current trapped
 *  count, and `drainSlots` is the fixed server-side drain-worker
 *  count (independent of `inhabitants`). Mirrors `HoneyPit.HoneyPit`
 *  with its `hCapacityPositive`, `hInhabitantsLeCapacity`, and
 *  `hDrainSlotsPositive` proof obligations.
 *
 *  Prefer `createHoneyPit` to enforce preconditions. */
export interface HoneyPit {
  readonly capacity: number;
  readonly inhabitants: number;
  readonly drainSlots: number;
}

/** Construct a `HoneyPit` with Lean-parity preconditions:
 *  `0 < capacity` (hCapacityPositive),
 *  `inhabitants ≤ capacity` (hInhabitantsLeCapacity),
 *  `0 < drainSlots` (hDrainSlotsPositive). `inhabitants` defaults to
 *  `0`. Throws `RangeError` on violation. */
export function createHoneyPit(
  capacity: number,
  drainSlots: number,
  inhabitants: number = 0
): HoneyPit {
  if (!Number.isInteger(capacity) || capacity < 1) {
    throw new RangeError(
      `HoneyPit capacity must be a positive integer, got ${capacity}`
    );
  }
  if (!Number.isInteger(drainSlots) || drainSlots < 1) {
    throw new RangeError(
      `HoneyPit drainSlots must be a positive integer, got ${drainSlots}`
    );
  }
  if (!Number.isInteger(inhabitants) || inhabitants < 0) {
    throw new RangeError(
      `HoneyPit inhabitants must be a non-negative integer, got ${inhabitants}`
    );
  }
  if (inhabitants > capacity) {
    throw new RangeError(
      `HoneyPit inhabitants ${inhabitants} exceeds capacity ${capacity}`
    );
  }
  return { capacity, inhabitants, drainSlots };
}

/** Mirror of `serverSlotCount` (Lean, HoneyPit) — returns
 *  `pit.drainSlots`, explicitly independent of `inhabitants`. One pool
 *  occupies one slot regardless of trapped connections. Cites
 *  `portPenaltyFree` and `sharedDrainInvariant`. */
export function serverSlotCount(pit: HoneyPit): number {
  return pit.drainSlots;
}

/** Mirror of `canTrap` (Lean) — true iff the pit has strictly fewer
 *  inhabitants than its capacity. Cites `poolOverflowGraceful`: a full
 *  pit reports `false`, so new arrivals fall through to a plain 403
 *  rather than unbounded server commitment. */
export function canTrap(pit: HoneyPit): boolean {
  return pit.inhabitants < pit.capacity;
}

/** Mirror of `trap` (Lean) — returns a new pit with `inhabitants + 1`,
 *  preserving `capacity` and `drainSlots`. Throws `RangeError` when
 *  `!canTrap(pit)`. Cites `sharedDrainInvariant` and
 *  `aikidoServerBound`: trapping preserves both `serverSlotCount` and
 *  `serverDrainWork`. */
export function trap(pit: HoneyPit): HoneyPit {
  if (!canTrap(pit)) {
    throw new RangeError(
      `HoneyPit is full (inhabitants=${pit.inhabitants}, capacity=${pit.capacity}); ` +
        `graceful-overflow contract requires caller to route to 403 instead of trap()`
    );
  }
  return {
    capacity: pit.capacity,
    inhabitants: pit.inhabitants + 1,
    drainSlots: pit.drainSlots,
  };
}

/** Mirror of `serverDrainWork` (Lean) — total server drain work over
 *  a horizon of `ticks`: `pit.drainSlots * ticks`. Clamped to zero for
 *  negative `ticks` (Lean uses `Nat`). Cites `aikidoServerBound`:
 *  independent of `inhabitants`. */
export function serverDrainWork(pit: HoneyPit, ticks: number): number {
  const t = Math.max(0, Math.floor(ticks));
  return pit.drainSlots * t;
}

/** Mirror of `attackerWait` (Lean) — linear lower bound on attacker
 *  cumulative wait across `k` trapped requests at iterate-depth
 *  `iterateDepth`: `k * iterateDepth`. Clamped to zero for negative
 *  inputs. Cites `aikidoAttackerBound` (monotone in `k`) and
 *  `trappedAttackerThroughputZero` (effective throughput zero in
 *  finite steps). */
export function attackerWait(k: number, iterateDepth: number): number {
  const kk = Math.max(0, Math.floor(k));
  const d = Math.max(0, Math.floor(iterateDepth));
  return kk * d;
}

// ─── Part IX: Linked Mesh Composition ─────────────────────────────────

/** A named binding from a source port in one mesh to a destination
 *  port in another. The overlay flags record whether the defender on
 *  the respective side has deployed an overlay covering the link
 *  target (pre-resolved per the `CompetingOverlayResolution`-style
 *  inclusion rule). Mirrors `LinkedMeshComposition.Link`.
 *
 *  Prefer `createLink` to enforce integer-index preconditions. */
export interface Link {
  readonly sourcePortIdx: number;
  readonly destPortIdx: number;
  readonly sourceOverlayCancelled: boolean;
  readonly destOverlayCancelled: boolean;
}

/** Construct a `Link` with non-negative-integer index preconditions.
 *  Overlay flags default to `false` (no cancellation). Throws
 *  `RangeError` on non-integer or negative indices. */
export function createLink(
  sourcePortIdx: number,
  destPortIdx: number,
  opts?: {
    sourceOverlayCancelled?: boolean;
    destOverlayCancelled?: boolean;
  }
): Link {
  if (!Number.isInteger(sourcePortIdx) || sourcePortIdx < 0) {
    throw new RangeError(
      `Link sourcePortIdx must be a non-negative integer, got ${sourcePortIdx}`
    );
  }
  if (!Number.isInteger(destPortIdx) || destPortIdx < 0) {
    throw new RangeError(
      `Link destPortIdx must be a non-negative integer, got ${destPortIdx}`
    );
  }
  return {
    sourcePortIdx,
    destPortIdx,
    sourceOverlayCancelled: opts?.sourceOverlayCancelled ?? false,
    destOverlayCancelled: opts?.destOverlayCancelled ?? false,
  };
}

/** Mirror of `linkAdmitted` (Lean) — four-way admission conjunction:
 *  source index inside `sourceMesh`'s port whitelist, destination
 *  index inside `destMesh`'s port whitelist, neither overlay
 *  cancelled. Cites `linkRequiresSourcePort`, `linkRequiresDestPort`,
 *  `linkHonorsSourceOverlay`, `linkHonorsDestOverlay`. */
export function linkAdmitted(
  sourceMesh: Mesh,
  destMesh: Mesh,
  link: Link
): boolean {
  return (
    link.sourcePortIdx < sourceMesh.portCount &&
    link.destPortIdx < destMesh.portCount &&
    !link.sourceOverlayCancelled &&
    !link.destOverlayCancelled
  );
}

/** Mirror of `pathAdmitted` (Lean, list-generalized form) — admission
 *  of the horizontal composition across `meshes[0] -[links[0]]->
 *  meshes[1] -[links[1]]-> ... -> meshes[N]`. Requires exactly
 *  `meshes.length === links.length + 1`; returns `false` on malformed
 *  shape. Default-deny propagates: every consecutive hop must admit.
 *
 *  Cites `compositionPreservesDefaultDenyLeft`,
 *  `compositionPreservesDefaultDenyRight` (denial on any hop denies
 *  the whole path) and `horizontalCompositionAssociative` (the list
 *  form agrees with the bundled three-mesh form, so the order of
 *  reduction across `&&` is immaterial). */
export function pathAdmitted(
  meshes: readonly Mesh[],
  links: readonly Link[]
): boolean {
  if (meshes.length !== links.length + 1) {
    return false;
  }
  for (let i = 0; i < links.length; i++) {
    const m1 = meshes[i];
    const m2 = meshes[i + 1];
    const l = links[i];
    if (m1 === undefined || m2 === undefined || l === undefined) {
      // Unreachable given the length invariant above, but satisfies
      // strict `noUncheckedIndexedAccess` should it be enabled.
      return false;
    }
    if (!linkAdmitted(m1, m2, l)) {
      return false;
    }
  }
  return true;
}

// ─── Part X: Anti-Vacuum Defenses ─────────────────────────────────────

/** An ablative surface: high outgassing prevents the structural formation
 *  of a VacuumAnchor. Mirrors `AntiVacuumDefenses.AblativeSurface`. */
export interface AblativeSurfaceCondition {
  readonly outgassingRate: number;
  readonly sealRate: number;
}

/**
 * Creates the Ablative Surface Condition.
 */
export function createAblativeSurfaceCondition(
  outgassingRate: number,
  sealRate: number
): AblativeSurfaceCondition {
  if (!Number.isInteger(outgassingRate) || outgassingRate < 0) {
    throw new RangeError(
      `AblativeSurface outgassingRate must be non-negative, got ${outgassingRate}`
    );
  }
  if (!Number.isInteger(sealRate) || sealRate < 0) {
    throw new RangeError(
      `AblativeSurface sealRate must be non-negative, got ${sealRate}`
    );
  }
  if (outgassingRate <= sealRate) {
    throw new RangeError(
      `Ablative surface must have outgassingRate strictly greater than sealRate (Lean hAblative)`
    );
  }
  return { outgassingRate, sealRate };
}

/** Mirror of `attemptSeal` (Lean) — if the surface is ablative, a
 *  vacuum seal inherently fails (returns false). */
export function attemptsSealOnAblative(
  surf: AblativeSurfaceCondition
): boolean {
  return false;
}

/** A Topo-Jitter condition: evaluates whether the defender clock oscillates
 *  mesh nodes faster than the attacker's anchor seal cycle.
 *  Mirrors `AntiVacuumDefenses.TopoJitter`. */
export interface TopoJitterCondition {
  readonly clockDefender: number;
  readonly clockAttacker: number;
}

/**
 * Creates the Topo Jitter Condition.
 */
export function createTopoJitterCondition(
  clockDefender: number,
  clockAttacker: number
): TopoJitterCondition {
  if (clockDefender <= clockAttacker) {
    throw new RangeError(
      `TopoJitter structure requires clockDefender > clockAttacker`
    );
  }
  return { clockDefender, clockAttacker };
}

/** Mirror of `jitterSeals` (Lean) — always returns false because
 *  the structural oscillation prevents the anchor. */
export function jitterSeals(j: TopoJitterCondition): boolean {
  return !(j.clockDefender > j.clockAttacker);
}

/** Void Mass tracking for Anomaly Telemetry.
 *  Mirrors `AntiVacuumDefenses.VoidMass`. */
export interface VoidMass {
  readonly mass: number;
}

/**
 * Creates the Void Mass.
 */
export function createVoidMass(mass: number): VoidMass {
  return { mass: Math.max(0, mass) };
}

/** Mirror of `pullVacuum` and `voidPressureAnomaly` (Lean) — tracks
 *  the anomaly generated by displacing the complement layer. */
export function voidPressureAnomaly(
  initial: VoidMass,
  vacuumVolume: number
): number {
  const currentMass = Math.max(0, initial.mass - vacuumVolume);
  return initial.mass - currentMass;
}

