/**
 * Handles the gnosis pressure Weighted Benchmark Topology Coordinates For workflow.
 */
export function pressureWeightedBenchmarkTopologyCoordinatesFor(
  interfereCoordinate: number
): readonly number[] {
  return [
    ...NATURAL_PORT_COORDINATES,
    Math.max(0, Math.floor(interfereCoordinate)),
  ];
}

/**
 * Handles the gnosis pressure Weighted Benchmark Interference Stride Trace For workflow.
 */
export function pressureWeightedBenchmarkInterferenceStrideTraceFor(
  interfereCoordinate: number
): readonly number[] {
  const anchor = Math.max(0, Math.floor(interfereCoordinate));
  return NATURAL_PORT_COORDINATES.map((coordinate) =>
    Math.max(0, anchor - coordinate)
  );
}

/**
 * Handles the gnosis pressure Weighted Benchmark Weighted Stride Trace For workflow.
 */
export function pressureWeightedBenchmarkWeightedStrideTraceFor(
  interfereCoordinate: number,
  leakageTrace: readonly number[] = EXACT_LEAKAGE_TRACE
): readonly number[] {
  const strideTrace =
    pressureWeightedBenchmarkInterferenceStrideTraceFor(interfereCoordinate);
  const count = Math.min(strideTrace.length, leakageTrace.length);
  return Array.from({ length: count }, (_, index) => {
    const stride = strideTrace[index] ?? 0;
    const leakagePressure = Math.max(0, Math.floor(leakageTrace[index] ?? 0));
    return stride * leakagePressure;
  });
}

/**
 * Handles the gnosis pressure Weighted Benchmark Total For workflow.
 */
export function pressureWeightedBenchmarkTotalFor(
  interfereCoordinate: number,
  leakageTrace: readonly number[] = EXACT_LEAKAGE_TRACE
): number {
  return pressureWeightedBenchmarkWeightedStrideTraceFor(
    interfereCoordinate,
    leakageTrace
  ).reduce((total, pressure) => total + pressure, 0);
}

