export interface SaturationObservation {
  readonly saturation: number;
  readonly expectedLayer: CosmosLayer | null;
  readonly focus: SieveFocus | null;
  /**
   * Lossy admit/reject collapse, preserved for the decision-tree and
   * reason-string consumers. `admitted === isAccept(verdict)`: an observation
   * that lands on a keystone gate is admitted; everything else (deferred OR
   * disqualified) collapses to `false`, exactly as before.
   */
  readonly admitted: boolean;
  /**
   * The canonical ternary lift of the lifecycle admission. A saturation that
   * lands on an exact keystone gate (10/30/90) is qualified + committed to a
   * layer → Accept. A finite saturation strictly inside the active keystone
   * band (between the first and last gate) but off any gate is qualified yet
   * contingent — it has not yet reached a scheduled layer → Abstain (defer).
   * Anything else (non-finite, negative, or outside the band) is disqualified
   * → Decline.
   */
  readonly verdict: Verdict;
}

