export interface BraidFoldAudit {
  /**
   * Lossy accept/reject collapse, preserved for the reason-string consumers.
   * `accepted === isAccept(verdict)`: only a fully certified candidate is
   * accepted; both hard structural rejections and deferred-pending-readiness
   * candidates collapse to `false`, exactly as before.
   */
  readonly accepted: boolean;
  /**
   * The canonical ternary lift of the audit. A fully certified candidate →
   * Accept. A candidate of the wrong canonical shape (gate coordinates,
   * saturation trace, or crossing count that can never be the braid fold) is
   * disqualified → Decline. A candidate of the RIGHT shape whose readiness
   * flags are not yet asserted (closed architecture / linked endpoints / base
   * readiness absent) is a genuine candidate that is simply unscheduled →
   * Abstain (defer): it may be re-audited once those flags are supplied.
   */
  readonly verdict: Verdict;
  readonly reason: string;
  readonly anchorCoordinates: readonly number[];
  readonly certificate: BraidFoldCertificate | null;
}

export interface DecompositionTripleAudit {
  readonly accepted: boolean;
  readonly reason: string;
  readonly coordinates: readonly number[];
  readonly certificate: DecompositionTripleCertificate | null;
}

