function isNonNegativeInteger(value: number): boolean {
  return Number.isInteger(value) && value >= 0;
}

function sameNumberTrace(
  left: readonly number[],
  right: readonly number[]
): boolean {
  return (
    left.length === right.length &&
    left.every((value, index) => value === right[index])
  );
}

function sameStringTrace(
  left: readonly string[],
  right: readonly string[]
): boolean {
  return (
    left.length === right.length &&
    left.every((value, index) => value === right[index])
  );
}

function anchorCoordinatesFromTrace(
  gateCoordinates: readonly number[]
): readonly number[] {
  return BRAID_FOLD_ANCHOR_COORDINATES.filter((coordinate) =>
    gateCoordinates.includes(coordinate)
  );
}

/**
 * Creates the Exact Decomposition Triple.
 */
export function createExactDecompositionTriple(): DecompositionTriple {
  return {
    decompositionGate: 7,
    raceAnchor: 17,
    foldAnchor: 22,
  };
}

/**
 * Handles the gnosis decomposition Triple Coordinates workflow.
 */
export function decompositionTripleCoordinates(
  triple: DecompositionTriple
): readonly number[] {
  return [triple.decompositionGate, triple.raceAnchor, triple.foldAnchor];
}

/**
 * Handles the gnosis decomposition Feeds Kenoma Span workflow.
 */
export function decompositionFeedsKenomaSpan(
  triple: DecompositionTriple
): boolean {
  return (
    triple.raceAnchor === triple.decompositionGate + layerCoordinate('kenoma')
  );
}

/**
 * Handles the gnosis decomposition Anchors Keystones workflow.
 */
export function decompositionAnchorsKeystones(
  triple: DecompositionTriple,
  certificate: BraidFoldCertificate | null
): boolean {
  return (
    certificate !== null &&
    triple.raceAnchor === certificate.layerCoordinates[2] &&
    triple.foldAnchor === certificate.layerCoordinates[3]
  );
}

/** Mirror of `CosmicArchitecture.layerCoordinate`. */
export function layerCoordinate(layer: CosmosLayer): number {
  switch (layer) {
    case 'kenoma':
      return 10;
    case 'localAeon':
      return 12;
    case 'primeKeystone':
      return 17;
    case 'doubleKeystone':
      return 22;
  }
}

/** Mirror of `SovereignSieve.expectedLayerForSaturation`. */
export function expectedLayerForSaturation(
  saturation: number
): CosmosLayer | null {
  switch (saturation) {
    case 10:
      return 'kenoma';
    case 30:
      return 'primeKeystone';
    case 90:
      return 'doubleKeystone';
    default:
      return null;
  }
}

/** Mirror of `SovereignSieve.focusForLayer`. */
export function focusForLayer(layer: CosmosLayer): SieveFocus {
  switch (layer) {
    case 'kenoma':
      return 'rawSubstrate';
    case 'localAeon':
      return 'observerResolution';
    case 'primeKeystone':
      return 'witnessInversion';
    case 'doubleKeystone':
      return 'hostHandshake';
  }
}

/** Mirror of `SovereignSieve.focusForSaturation`. */
export function focusForSaturation(saturation: number): SieveFocus | null {
  const layer = expectedLayerForSaturation(saturation);
  return layer === null ? null : focusForLayer(layer);
}

/**
 * Handles the gnosis observe Saturation workflow.
 */
export function observeSaturation(saturation: number): SaturationObservation {
  const expectedLayer = expectedLayerForSaturation(saturation);
  return {
    saturation,
    expectedLayer,
    focus: expectedLayer === null ? null : focusForLayer(expectedLayer),
    admitted: expectedLayer !== null,
    verdict: saturationAdmissionVerdict(saturation, expectedLayer),
  };
}

/**
 * The ternary lift of the saturation lifecycle admission. On-gate → Accept;
 * finite and strictly inside the keystone band but off-gate → Abstain (defer);
 * otherwise → Decline. The keystone band is `[first gate, last gate]` of the
 * exact saturation trace, so the neutral middle is a real, reachable third
 * state (e.g. saturation 12 sits between gates 10 and 30 → Abstain), not an
 * invented one. `isAccept(verdict)` reproduces the legacy `admitted` boolean.
 */
function saturationAdmissionVerdict(
  saturation: number,
  expectedLayer: CosmosLayer | null
): Verdict {
  if (expectedLayer !== null) {
    return Verdict.Accept;
  }
  const firstGate = EXACT_SATURATION_TRACE[0];
  const lastGate = EXACT_SATURATION_TRACE[EXACT_SATURATION_TRACE.length - 1];
  if (
    Number.isFinite(saturation) &&
    saturation > firstGate &&
    lastGate !== undefined &&
    saturation < lastGate
  ) {
    return Verdict.Abstain;
  }
  return Verdict.Decline;
}

/** Mirror of `StatisticalMechanicsAccounting.visibleMass`. */
export function visibleMass(
  saturation: number,
  rowBudget = LOCAL_AEON_ROW_BUDGET
): number {
  return Math.min(saturation, rowBudget);
}

/** Mirror of `StatisticalMechanicsAccounting.leakage`. */
export function leakage(
  saturation: number,
  rowBudget = LOCAL_AEON_ROW_BUDGET
): number {
  return Math.max(0, saturation - rowBudget);
}

/** Mirror of `StatisticalMechanicsAccounting.informationMass`. */
export function informationMass(
  saturation: number,
  topologicalVolume = STATISTICAL_TOPOLOGICAL_VOLUME
): number {
  return saturation * topologicalVolume;
}

/** Mirror of `StatisticalMechanicsAccounting.leakageMass`. */
export function leakageMass(
  saturation: number,
  topologicalVolume = STATISTICAL_TOPOLOGICAL_VOLUME
): number {
  return leakage(saturation) * topologicalVolume;
}

