/**
 * Handles the gnosis trace Total workflow.
 */
export function traceTotal(trace: readonly number[]): number {
  return trace.reduce((sum, value) => sum + value, 0);
}

/** Mirror of `CosmicArchitecture.keystoneGap` over explicit coordinates. */
export function keystoneGap(
  primeKeystone: number,
  doubleKeystone: number
): number {
  return Math.max(0, doubleKeystone - primeKeystone);
}

/**
 * Handles the gnosis port Coordinate For Action workflow.
 */
export function portCoordinateForAction(action: BraidPortAction): number {
  switch (action) {
    case 'fork':
      return 10;
    case 'race':
      return 12;
    case 'fold':
      return 17;
    case 'vent':
      return 22;
    case 'interfere':
      return GNOSIS_URING_INTERFERE_PORT_COORDINATE;
  }
}

