/**
 * Handles the gnosis returns To Base workflow.
 */
export function returnsToBase(
  certificate:
    | ClosedArchitectureCertificate
    | NaturalPortSystemCertificate
    | BraidFoldCertificate
    | DecompositionTripleCertificate
    | BraidPacketCertificate
    | ExtendedAeonTransitionCertificate
    | IndexedInterferePortClosureFamilyCertificate
    | IndexedInterferePortClosureFamilyAuditCertificate
    | IndexedInterferePortClosureFamilyRejectionCertificate
    | IndexedInterferePortAdmissionCertificate
    | GnosisUringInterferePortCertificate
    | InterferenceStrideCertificate
    | PressureWeightedInterferenceStrideCertificate
    | GnosticLensGeometryCertificate
    | ClosedLoopRuntimeMetadataCertificate
    | PressureWeightedClosedLoopBenchmarkReportCertificate
    | PressureCertifiedExecutionPathCertificate
    | WankelRuntimeCertificate
    | StatisticalMechanicsAccountingCertificate
    | GnosticMetrologyProfile
    | PressureGradientCertificate
    | FluidicRoutingAdmissibilityCertificate
): boolean {
  return certificate.returnsToBase;
}

function layerCoordinatesFromAccountingSource(
  certificate:
    | ClosedArchitectureCertificate
    | BraidFoldCertificate
    | DecompositionTripleCertificate
): readonly number[] {
  if (certificate.source === 'GnosisDecompositionTripleCertificate') {
    return certificate.braidFoldCertificate.layerCoordinates;
  }
  return certificate.layerCoordinates;
}

function saturationTraceFromAccountingSource(
  certificate:
    | ClosedArchitectureCertificate
    | BraidFoldCertificate
    | DecompositionTripleCertificate
): readonly number[] {
  if (certificate.source === 'GnosisDecompositionTripleCertificate') {
    return certificate.braidFoldCertificate.saturationTrace;
  }
  return certificate.saturationTrace;
}

/**
 * Creates the Statistical Mechanics Accounting.
 */
export function createStatisticalMechanicsAccounting(
  certificate:
    | ClosedArchitectureCertificate
    | BraidFoldCertificate
    | DecompositionTripleCertificate
    | null = createClosedArchitectureCertificate()
): StatisticalMechanicsAccountingCertificate | null {
  if (certificate === null || !returnsToBase(certificate)) {
    return null;
  }

  const layerCoordinates = layerCoordinatesFromAccountingSource(certificate);
  const saturationTrace = saturationTraceFromAccountingSource(certificate);
  if (
    !sameNumberTrace(layerCoordinates, EXACT_LAYER_COORDINATES) ||
    !sameNumberTrace(saturationTrace, EXACT_SATURATION_TRACE)
  ) {
    return null;
  }

  const visibleTrace = visibleMassTrace(saturationTrace);
  const leakagePressureTrace = leakageTrace(saturationTrace);
  const massTrace = informationMassTrace(saturationTrace);
  const leakageDensityTrace = leakageMassTrace(saturationTrace);

  if (
    !sameNumberTrace(visibleTrace, EXACT_VISIBLE_MASS_TRACE) ||
    !sameNumberTrace(leakagePressureTrace, EXACT_LEAKAGE_TRACE) ||
    !sameNumberTrace(massTrace, EXACT_INFORMATION_MASS_TRACE) ||
    !sameNumberTrace(leakageDensityTrace, EXACT_LEAKAGE_MASS_TRACE)
  ) {
    return null;
  }

  return {
    source: 'GnosisStatisticalMechanicsAccountingCertificate',
    layerCoordinates: EXACT_LAYER_COORDINATES,
    saturationTrace: EXACT_SATURATION_TRACE,
    visibleRowBudget: LOCAL_AEON_ROW_BUDGET,
    topologicalVolume: STATISTICAL_TOPOLOGICAL_VOLUME,
    visibleMassTrace: EXACT_VISIBLE_MASS_TRACE,
    leakageTrace: EXACT_LEAKAGE_TRACE,
    informationMassTrace: EXACT_INFORMATION_MASS_TRACE,
    leakageMassTrace: EXACT_LEAKAGE_MASS_TRACE,
    totalLeakage: 96,
    totalInformationMass: 1560,
    constrainedByWitnesses: true,
    returnsToBase: true,
    theoremIds: STATISTICAL_MECHANICS_THEOREM_IDS,
  };
}

/**
 * Creates the Braid Packet Certificate.
 */
export function createBraidPacketCertificate(
  cycle: number,
  accounting: StatisticalMechanicsAccountingCertificate | null = createStatisticalMechanicsAccounting()
): BraidPacketCertificate | null {
  if (!isNonNegativeInteger(cycle)) {
    return null;
  }
  if (accounting === null || !returnsToBase(accounting)) {
    return null;
  }

  const boundary = createVentToForkBoundary();
  const boundaryMatchesStream =
    boundary.outgoingStage + 1 === boundary.incomingStage &&
    infiniteForkRaceFoldVentAction(boundary.outgoingStage) ===
      boundary.outgoingAction &&
    infiniteForkRaceFoldVentAction(boundary.incomingStage) ===
      boundary.incomingAction &&
    infiniteForkRaceFoldVentCoordinate(boundary.outgoingStage) ===
      boundary.outgoingCoordinate &&
    infiniteForkRaceFoldVentCoordinate(boundary.incomingStage) ===
      boundary.incomingCoordinate &&
    nextPortAction(boundary.outgoingAction) === boundary.incomingAction;
  if (!boundaryMatchesStream) {
    return null;
  }

  if (
    !sameNumberTrace(accounting.layerCoordinates, NATURAL_PORT_COORDINATES) ||
    !sameNumberTrace(accounting.saturationTrace, EXACT_SATURATION_TRACE) ||
    !sameNumberTrace(
      accounting.informationMassTrace,
      EXACT_INFORMATION_MASS_TRACE
    ) ||
    !sameNumberTrace(accounting.leakageTrace, EXACT_LEAKAGE_TRACE) ||
    accounting.totalInformationMass !== 1560 ||
    accounting.totalLeakage !== 96
  ) {
    return null;
  }

  return {
    source: 'GnosisBraidPacketCertificate',
    cycle,
    actionTrace: EXACT_PORT_ACTION_TRACE,
    portCoordinates: NATURAL_PORT_COORDINATES,
    saturationTrace: EXACT_SATURATION_TRACE,
    informationMassTrace: EXACT_INFORMATION_MASS_TRACE,
    leakageTrace: EXACT_LEAKAGE_TRACE,
    totalInformationMass: 1560,
    totalLeakage: 96,
    boundary,
    accounting,
    returnsToBase: true,
    theoremIds: BRAID_PACKET_THEOREM_IDS,
  };
}

/**
 * Creates the Extended Aeon Transition Certificate.
 */
export function createExtendedAeonTransitionCertificate(
  braidPacket: BraidPacketCertificate | null = createBraidPacketCertificate(0)
): ExtendedAeonTransitionCertificate | null {
  if (braidPacket === null || !returnsToBase(braidPacket)) {
    return null;
  }
  const primeTransition: ExtendedAeonPrimeTransition = {
    aeon: 'fourth',
    linearTerminal: 42,
    clinamen: 1,
    terminal: 43,
    foldKeystone: 37,
    ventKeystone: 43,
  };
  const transitionValid =
    primeTransition.linearTerminal + primeTransition.clinamen ===
      primeTransition.terminal &&
    primeTransition.terminal === 43 &&
    primeTransition.foldKeystone === 37 &&
    primeTransition.ventKeystone === 43;
  const closure = {
    coordinate: 55,
    carrier: 11,
    cycles: 5,
  } as const;
  const closureValid = closure.coordinate === closure.carrier * closure.cycles;
  if (
    !transitionValid ||
    !closureValid ||
    braidPacket.totalInformationMass !== 1560 ||
    braidPacket.totalLeakage !== 96
  ) {
    return null;
  }

  return {
    source: 'GnosisExtendedAeonTransitionCertificate',
    ranges: EXACT_EXTENDED_AEON_RANGES,
    keystoneTrace: EXACT_EXTENDED_AEON_KEYSTONE_TRACE,
    primeTransition,
    closure,
    braidPacket,
    returnsToBase: true,
    theoremIds: EXTENDED_AEON_TRANSITION_THEOREM_IDS,
  };
}

/**
 * Creates the Indexed Interfere Port Admission Certificate.
 */
export function createIndexedInterferePortAdmissionCertificate(
  transition: ExtendedAeonTransitionCertificate | null = createExtendedAeonTransitionCertificate(),
  portCoordinate: number = GNOSIS_URING_INTERFERE_PORT_COORDINATE,
  closureCoordinate: number = GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
  closureIndex: number = INTERFERENCE_CLOSURE_FAMILY_INDEX
): IndexedInterferePortAdmissionCertificate | null {
  const closureFamily = createIndexedInterferePortClosureFamilyCertificate(
    transition,
    portCoordinate,
    closureIndex
  );
  if (closureFamily === null) {
    return null;
  }

  if (
    !Number.isInteger(closureCoordinate) ||
    closureCoordinate !== closureFamily.closureCoordinate ||
    closureCoordinate !== GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE ||
    closureFamily.closureIndex !== INTERFERENCE_CLOSURE_FAMILY_INDEX ||
    !closureFamily.exactAdmissionCompatible
  ) {
    return null;
  }

  return {
    source: 'GnosisIndexedInterferePortAdmissionCertificate',
    portAction: 'interfere',
    portCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    closureIndex: INTERFERENCE_CLOSURE_FAMILY_INDEX,
    closureStride: INTERFERENCE_CLOSURE_STRIDE,
    closureFamily,
    terminal: true,
    transition: closureFamily.transition,
    returnsToBase: true,
    theoremIds: INDEXED_INTERFERE_PORT_ADMISSION_THEOREM_IDS,
  };
}

function indexedInterfereClosureCoordinateFor(
  portCoordinate: number,
  closureIndex: number
): number {
  return portCoordinate + closureIndex * INTERFERENCE_CLOSURE_STRIDE;
}

function closureFamilyPressureTotalFor(
  members: readonly IndexedInterferePortClosureFamilyCertificate[]
): number {
  return traceTotal(
    members.map((member) => member.closureAxisPressureWeightedTotal)
  );
}

/**
 * Creates the Indexed Interfere Port Closure Family Certificate.
 */
export function createIndexedInterferePortClosureFamilyCertificate(
  transition: ExtendedAeonTransitionCertificate | null = createExtendedAeonTransitionCertificate(),
  portCoordinate: number = GNOSIS_URING_INTERFERE_PORT_COORDINATE,
  closureIndex: number = INTERFERENCE_CLOSURE_FAMILY_INDEX
): IndexedInterferePortClosureFamilyCertificate | null {
  if (transition === null || !returnsToBase(transition)) {
    return null;
  }
  if (
    !Number.isInteger(portCoordinate) ||
    !Number.isInteger(closureIndex) ||
    portCoordinate !== GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    transition.primeTransition.terminal !== portCoordinate ||
    transition.primeTransition.ventKeystone !== portCoordinate ||
    nextPortAction('interfere') !== 'interfere' ||
    closureIndex < INTERFERENCE_CLOSURE_FAMILY_INDEX ||
    closureIndex > MAX_BOUNDED_INTERFERENCE_CLOSURE_FAMILY_INDEX
  ) {
    return null;
  }

  const exactAdmissionCompatible =
    closureIndex === INTERFERENCE_CLOSURE_FAMILY_INDEX;
  const closureStepsAfterExactAdmission = Math.max(
    0,
    closureIndex - INTERFERENCE_CLOSURE_FAMILY_INDEX
  );
  const closureDistanceFromExactAdmission =
    closureStepsAfterExactAdmission * INTERFERENCE_CLOSURE_STRIDE;
  const closureCoordinate = indexedInterfereClosureCoordinateFor(
    GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureIndex
  );
  const closureAxisPressureWeightedTotal =
    pressureWeightedBenchmarkTotalFor(closureCoordinate);
  const closureAxisPressureGrowthFromInterferencePort =
    closureIndex * INTERFERENCE_CLOSURE_PRESSURE_GROWTH_BLOCK;
  const closureAxisPressureGrowthFromExactClosure =
    closureStepsAfterExactAdmission *
    INTERFERENCE_CLOSURE_PRESSURE_GROWTH_BLOCK;
  const theoremIds = exactAdmissionCompatible
    ? INDEXED_INTERFERE_PORT_FIRST_CLOSURE_FAMILY_THEOREM_IDS
    : closureIndex === SECOND_INTERFERENCE_CLOSURE_FAMILY_INDEX
    ? INDEXED_INTERFERE_PORT_SECOND_CLOSURE_FAMILY_THEOREM_IDS
    : closureIndex === THIRD_INTERFERENCE_CLOSURE_FAMILY_INDEX
    ? INDEXED_INTERFERE_PORT_THIRD_CLOSURE_FAMILY_THEOREM_IDS
    : INDEXED_INTERFERE_PORT_CLOSURE_FAMILY_THEOREM_IDS;
  return {
    source: 'GnosisIndexedInterferePortClosureFamilyCertificate',
    portAction: 'interfere',
    portCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureCoordinate,
    closureIndex,
    closureStride: INTERFERENCE_CLOSURE_STRIDE,
    closureStepsAfterExactAdmission,
    closureDistanceFromExactAdmission,
    closureAxisPressureWeightedTotal,
    closureAxisPressureGrowthFromInterferencePort,
    closureAxisPressureGrowthFromExactClosure,
    orderedAfterExactAdmission:
      closureIndex > INTERFERENCE_CLOSURE_FAMILY_INDEX,
    terminal: true,
    exactAdmissionCompatible,
    transition,
    returnsToBase: true,
    theoremIds,
  };
}

/**
 * Creates the Indexed Interfere Port Closure Family Audit Certificate.
 */
export function createIndexedInterferePortClosureFamilyAuditCertificate(
  transition: ExtendedAeonTransitionCertificate | null = createExtendedAeonTransitionCertificate(),
  closureIndices: readonly number[] = BOUNDED_INTERFERENCE_CLOSURE_FAMILY_INDICES
): IndexedInterferePortClosureFamilyAuditCertificate | null {
  if (transition === null || !returnsToBase(transition)) {
    return null;
  }
  if (
    closureIndices.length === 0 ||
    closureIndices.some(
      (closureIndex) =>
        !Number.isInteger(closureIndex) ||
        closureIndex < INTERFERENCE_CLOSURE_FAMILY_INDEX ||
        closureIndex > MAX_BOUNDED_INTERFERENCE_CLOSURE_FAMILY_INDEX
    )
  ) {
    return null;
  }

  const members = closureIndices.map((closureIndex) =>
    createIndexedInterferePortClosureFamilyCertificate(
      transition,
      GNOSIS_URING_INTERFERE_PORT_COORDINATE,
      closureIndex
    )
  );
  if (members.some((member) => member === null)) {
    return null;
  }
  const certifiedMembers =
    members as IndexedInterferePortClosureFamilyCertificate[];
  const formulasHold = certifiedMembers.every((member) => {
    const expectedCoordinate = indexedInterfereClosureCoordinateFor(
      GNOSIS_URING_INTERFERE_PORT_COORDINATE,
      member.closureIndex
    );
    const stepsAfterExact = Math.max(
      0,
      member.closureIndex - INTERFERENCE_CLOSURE_FAMILY_INDEX
    );
    return (
      member.closureCoordinate === expectedCoordinate &&
      member.closureDistanceFromExactAdmission ===
        stepsAfterExact * INTERFERENCE_CLOSURE_STRIDE &&
      member.closureAxisPressureWeightedTotal ===
        EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL +
          member.closureIndex * INTERFERENCE_CLOSURE_PRESSURE_GROWTH_BLOCK &&
      member.closureAxisPressureGrowthFromInterferencePort ===
        member.closureIndex * INTERFERENCE_CLOSURE_PRESSURE_GROWTH_BLOCK &&
      member.closureAxisPressureGrowthFromExactClosure ===
        stepsAfterExact * INTERFERENCE_CLOSURE_PRESSURE_GROWTH_BLOCK &&
      member.exactAdmissionCompatible ===
        (member.closureIndex === INTERFERENCE_CLOSURE_FAMILY_INDEX)
    );
  });
  if (!formulasHold) {
    return null;
  }
  const closureFamilyPressureTotal =
    closureFamilyPressureTotalFor(certifiedMembers);

  const theoremIds = sameNumberTrace(
    closureIndices,
    BOUNDED_INTERFERENCE_CLOSURE_FAMILY_INDICES
  )
    ? BOUNDED_INDEXED_INTERFERE_PORT_CLOSURE_FAMILY_AUDIT_THEOREM_IDS
    : INDEXED_INTERFERE_PORT_CLOSURE_FAMILY_AUDIT_THEOREM_IDS;

  return {
    source: 'GnosisIndexedInterferePortClosureFamilyAuditCertificate',
    portAction: 'interfere',
    portCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureStride: INTERFERENCE_CLOSURE_STRIDE,
    maxClosureIndex: MAX_BOUNDED_INTERFERENCE_CLOSURE_FAMILY_INDEX,
    closureIndices: [...closureIndices],
    members: certifiedMembers,
    pressureGrowthBlock: INTERFERENCE_CLOSURE_PRESSURE_GROWTH_BLOCK,
    closureFamilyPressureTotal,
    pressureUnit: SIEVE_PASCAL_UNIT,
    exactAdmissionClosureIndex: INTERFERENCE_CLOSURE_FAMILY_INDEX,
    exactAdmissionClosureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    returnsToBase: true,
    theoremIds,
  };
}

/**
 * Creates the Indexed Interfere Port Closure Family Rejection Certificate.
 */
export function createIndexedInterferePortClosureFamilyRejectionCertificate(
  family: IndexedInterferePortClosureFamilyCertificate | null = createIndexedInterferePortClosureFamilyCertificate(
    createExtendedAeonTransitionCertificate(),
    GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    SECOND_INTERFERENCE_CLOSURE_FAMILY_INDEX
  )
): IndexedInterferePortClosureFamilyRejectionCertificate | null {
  if (
    family === null ||
    !returnsToBase(family) ||
    family.exactAdmissionCompatible ||
    family.closureIndex <= INTERFERENCE_CLOSURE_FAMILY_INDEX ||
    family.closureIndex > MAX_BOUNDED_INTERFERENCE_CLOSURE_FAMILY_INDEX ||
    family.closureCoordinate !==
      indexedInterfereClosureCoordinateFor(
        GNOSIS_URING_INTERFERE_PORT_COORDINATE,
        family.closureIndex
      )
  ) {
    return null;
  }

  return {
    source: 'GnosisIndexedInterferePortClosureFamilyRejectionCertificate',
    rejectedBy: 'GnosisIndexedInterferePortAdmissionCertificate',
    reason: 'wrong-closure-index',
    expectedClosureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    expectedClosureIndex: INTERFERENCE_CLOSURE_FAMILY_INDEX,
    family,
    closureDistanceFromExactAdmission: family.closureDistanceFromExactAdmission,
    returnsToBase: true,
    theoremIds: INDEXED_INTERFERE_PORT_WRONG_CLOSURE_REJECTION_THEOREM_IDS,
  };
}

/**
 * Creates the Gnosis Uring Interfere Port Certificate.
 */
export function createGnosisUringInterferePortCertificate(
  transition: ExtendedAeonTransitionCertificate | null = createExtendedAeonTransitionCertificate()
): GnosisUringInterferePortCertificate | null {
  if (transition === null || !returnsToBase(transition)) {
    return null;
  }
  const indexedAdmission =
    createIndexedInterferePortAdmissionCertificate(transition);
  const closureFamilyAudit =
    createIndexedInterferePortClosureFamilyAuditCertificate(transition);
  if (
    indexedAdmission === null ||
    closureFamilyAudit === null ||
    portCoordinateForAction('interfere') !==
      GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    actionForPortCoordinate(GNOSIS_URING_INTERFERE_PORT_COORDINATE) !==
      'interfere' ||
    nextPortAction('interfere') !== 'interfere' ||
    transition.primeTransition.terminal !==
      GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    transition.primeTransition.ventKeystone !==
      GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    transition.closure.coordinate !== GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE
  ) {
    return null;
  }

  return {
    source: 'GnosisUringInterferePortCertificate',
    host: 'gnosis-uring',
    portAction: 'interfere',
    portCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    terminal: true,
    indexedAdmission,
    closureFamilyAudit,
    transition,
    returnsToBase: true,
    theoremIds: GNOSIS_URING_INTERFERE_PORT_THEOREM_IDS,
  };
}

/**
 * Creates the Interference Stride Certificate.
 */
export function createInterferenceStrideCertificate(
  braidPacket: BraidPacketCertificate | null = createBraidPacketCertificate(0)
): InterferenceStrideCertificate | null {
  if (braidPacket === null || !returnsToBase(braidPacket)) {
    return null;
  }
  const strideTrace = NATURAL_PORT_COORDINATES.map(
    (coordinate) => GNOSIS_URING_INTERFERE_PORT_COORDINATE - coordinate
  );
  if (
    !sameNumberTrace(braidPacket.portCoordinates, NATURAL_PORT_COORDINATES) ||
    !sameNumberTrace(strideTrace, EXACT_INTERFERENCE_STRIDE_TRACE) ||
    braidPacket.totalInformationMass !== 1560 ||
    braidPacket.totalLeakage !== 96 ||
    NATURAL_PORT_COORDINATES.some(
      (coordinate: number) =>
        coordinate === GNOSIS_URING_INTERFERE_PORT_COORDINATE
    ) ||
    actionForPortCoordinate(GNOSIS_URING_INTERFERE_PORT_COORDINATE) !==
      'interfere' ||
    nextPortAction('interfere') !== 'interfere'
  ) {
    return null;
  }

  return {
    source: 'GnosisInterferenceStrideCertificate',
    portAction: 'interfere',
    anchorCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    naturalCoordinates: NATURAL_PORT_COORDINATES,
    strideTrace: EXACT_INTERFERENCE_STRIDE_TRACE,
    externalToNaturalStack: true,
    terminal: true,
    braidPacket,
    returnsToBase: true,
    theoremIds: INTERFERENCE_STRIDE_THEOREM_IDS,
  };
}

/**
 * Creates the Pressure Weighted Interference Stride Certificate.
 */
export function createPressureWeightedInterferenceStrideCertificate(
  interferenceStride: InterferenceStrideCertificate | null = createInterferenceStrideCertificate()
): PressureWeightedInterferenceStrideCertificate | null {
  if (interferenceStride === null || !returnsToBase(interferenceStride)) {
    return null;
  }
  const leakageTrace = interferenceStride.braidPacket.leakageTrace;
  const leakageTotal = traceTotal(leakageTrace);
  const weightedPressureTrace: readonly [number, number, number] = [
    interferenceStride.strideTrace[0] * leakageTrace[0],
    interferenceStride.strideTrace[1] * leakageTrace[1],
    interferenceStride.strideTrace[2] * leakageTrace[2],
  ];
  const weightedPressureTotal = traceTotal(weightedPressureTrace);
  if (
    !sameNumberTrace(
      interferenceStride.strideTrace,
      EXACT_INTERFERENCE_STRIDE_TRACE
    ) ||
    !sameNumberTrace(leakageTrace, EXACT_LEAKAGE_TRACE) ||
    leakageTotal !== 96 ||
    !sameNumberTrace(
      weightedPressureTrace,
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_STRIDE_TRACE
    ) ||
    weightedPressureTotal !== EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL
  ) {
    return null;
  }

  return {
    source: 'GnosisPressureWeightedInterferenceStrideCertificate',
    portAction: 'interfere',
    anchorCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    strideTrace: EXACT_INTERFERENCE_STRIDE_TRACE,
    leakageTrace: EXACT_LEAKAGE_TRACE,
    leakageTotal: 96,
    weightedPressureTrace: EXACT_PRESSURE_WEIGHTED_INTERFERENCE_STRIDE_TRACE,
    weightedPressureTotal: EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL,
    pressureUnit: SIEVE_PASCAL_UNIT,
    weighting: 'stride-leakage-zip',
    interferenceStride,
    returnsToBase: true,
    theoremIds: PRESSURE_WEIGHTED_INTERFERENCE_STRIDE_THEOREM_IDS,
  };
}

function fullQuadraticRotationWork(degrees: number): number {
  return degrees * degrees;
}

function quotientQuadraticRotationWork(
  sampledDegrees: number,
  fullRotationDegrees: number
): number {
  return sampledDegrees * fullRotationDegrees;
}

/**
 * Creates the Gnostic Lens Geometry Certificate.
 */
export function createGnosticLensGeometryCertificate(
  braidPacket: BraidPacketCertificate | null = createBraidPacketCertificate(0)
): GnosticLensGeometryCertificate | null {
  if (braidPacket === null || !returnsToBase(braidPacket)) {
    return null;
  }

  const pinkFullQuadraticWork = fullQuadraticRotationWork(360);
  const pinkQuotientQuadraticWork = quotientQuadraticRotationWork(180, 360);
  const pinkHalvesQuadraticWork =
    pinkQuotientQuadraticWork * 2 === pinkFullQuadraticWork;
  const pinkReducesWork = pinkQuotientQuadraticWork < pinkFullQuadraticWork;
  const brownFullQuadraticWork = fullQuadraticRotationWork(1080);
  const brownQuotientQuadraticWork = quotientQuadraticRotationWork(540, 1080);
  const brownHalvesQuadraticWork =
    brownQuotientQuadraticWork * 2 === brownFullQuadraticWork;
  const brownReducesWork = brownQuotientQuadraticWork < brownFullQuadraticWork;
  const pinkShortcut: FiniteSphericalHarmonicShortcutMirror = {
    shell: 'pink',
    fullRotationDegrees: 360,
    sampledDegrees: 180,
    mirroredDegrees: 180,
    quotientFactor: 2,
    fullQuadraticWork: pinkFullQuadraticWork,
    quotientQuadraticWork: pinkQuotientQuadraticWork,
    halvesQuadraticWork: true,
    reducesWork: true,
  };
  const brownShortcut: FiniteSphericalHarmonicShortcutMirror = {
    shell: 'brown',
    fullRotationDegrees: 1080,
    sampledDegrees: 540,
    mirroredDegrees: 540,
    quotientFactor: 2,
    fullQuadraticWork: brownFullQuadraticWork,
    quotientQuadraticWork: brownQuotientQuadraticWork,
    halvesQuadraticWork: true,
    reducesWork: true,
  };
  const portLensObservations: readonly [
    PortLensObservationMirror,
    PortLensObservationMirror,
    PortLensObservationMirror,
    PortLensObservationMirror,
    PortLensObservationMirror
  ] = [
    { role: 'forkCore', coordinate: 10, shape: 'plane' },
    { role: 'racePlane', coordinate: 12, shape: 'plane' },
    { role: 'foldTwist', coordinate: 17, shape: 'torus' },
    { role: 'ventExit', coordinate: 22, shape: 'torus' },
    { role: 'interferenceAxis', coordinate: 43, shape: 'singularAxis' },
  ];
  const portLensObservationCoordinates = portLensObservations.map(
    (observation) => observation.coordinate
  );
  const portLensObservationShapes = portLensObservations.map(
    (observation) => observation.shape
  );
  const closureStride =
    GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE -
    GNOSIS_URING_INTERFERE_PORT_COORDINATE;

  if (
    !sameNumberTrace(braidPacket.portCoordinates, NATURAL_PORT_COORDINATES) ||
    !sameNumberTrace(braidPacket.saturationTrace, EXACT_SATURATION_TRACE) ||
    !sameNumberTrace(
      braidPacket.informationMassTrace,
      EXACT_INFORMATION_MASS_TRACE
    ) ||
    !sameNumberTrace(braidPacket.leakageTrace, EXACT_LEAKAGE_TRACE) ||
    braidPacket.totalInformationMass !== 1560 ||
    braidPacket.totalLeakage !== 96 ||
    traceTotal(EXACT_INFORMATION_MASS_TRACE) !== 1560 ||
    LOCAL_AEON_ROW_BUDGET !== 12 ||
    1560 / LOCAL_AEON_ROW_BUDGET !== EXACT_PACKED_GEOMETRY_BUCKET_WEIGHT ||
    EXACT_SPHERICAL_ROTATION_TRACE[1] !== 360 ||
    EXACT_SPHERICAL_ROTATION_TRACE[2] !==
      3 * EXACT_SPHERICAL_ROTATION_TRACE[1] ||
    !sameNumberTrace(EXACT_LENS_OBSERVATION_COORDINATES, [12, 30, 90, 43]) ||
    !sameStringTrace(EXACT_LENS_OBSERVATION_SHAPES, [
      'plane',
      'sphere',
      'torus',
      'singularAxis',
    ]) ||
    !sameNumberTrace(
      portLensObservationCoordinates,
      EXACT_PORT_LENS_OBSERVATION_COORDINATES
    ) ||
    !sameStringTrace(
      portLensObservationShapes,
      EXACT_PORT_LENS_OBSERVATION_SHAPES
    ) ||
    lensShapeForPortCoordinate(10) !== 'plane' ||
    lensShapeForPortCoordinate(12) !== 'plane' ||
    lensShapeForPortCoordinate(17) !== 'torus' ||
    lensShapeForPortCoordinate(22) !== 'torus' ||
    lensShapeForPortCoordinate(43) !== 'singularAxis' ||
    PERFECT_LOCAL_DOUBLE_COVER_COORDINATE !== 2 * LOCAL_AEON_ROW_BUDGET ||
    DOUBLE_KEYSTONE_COVER_DEFICIT !==
      PERFECT_LOCAL_DOUBLE_COVER_COORDINATE - 22 ||
    closureStride !== INTERFERENCE_CLOSURE_STRIDE ||
    closureStride !== LOCAL_AEON_ROW_BUDGET ||
    !pinkHalvesQuadraticWork ||
    !brownHalvesQuadraticWork ||
    !pinkReducesWork ||
    !brownReducesWork
  ) {
    return null;
  }

  return {
    source: 'GnosisGnosticLensGeometryCertificate',
    sphericalAccountingTrace: [
      {
        layer: 'kenomaCore',
        shape: 'trianglePlane',
        saturation: 10,
        informationMass: 120,
        rotationDegrees: 120,
        wrapCount: 1,
      },
      {
        layer: 'pinkShell',
        shape: 'informationSphere',
        saturation: 30,
        informationMass: 360,
        rotationDegrees: 360,
        wrapCount: 1,
      },
      {
        layer: 'brownAura',
        shape: 'toroidalBraid',
        saturation: 90,
        informationMass: 1080,
        rotationDegrees: 1080,
        wrapCount: 3,
      },
    ],
    sphericalSaturationTrace: EXACT_SATURATION_TRACE,
    sphericalInformationMassTrace: EXACT_INFORMATION_MASS_TRACE,
    sphericalRotationTrace: EXACT_SPHERICAL_ROTATION_TRACE,
    sphericalWrapTrace: EXACT_SPHERICAL_WRAP_TRACE,
    packedGeometryTotalMass: 1560,
    packedGeometryBucketWeight: EXACT_PACKED_GEOMETRY_BUCKET_WEIGHT,
    highLatitudePortCoordinates: [17, 22],
    harmonicShortcuts: [pinkShortcut, brownShortcut],
    lensObservationCoordinates: EXACT_LENS_OBSERVATION_COORDINATES,
    lensObservationShapes: EXACT_LENS_OBSERVATION_SHAPES,
    portLensObservationCoordinates: EXACT_PORT_LENS_OBSERVATION_COORDINATES,
    portLensObservationShapes: EXACT_PORT_LENS_OBSERVATION_SHAPES,
    portLensObservations,
    nestedGeometry: {
      enclosureShape: 'sphere',
      braidShape: 'torus',
      enclosureRotationDegrees: 360,
      braidRotationDegrees: 1080,
      braidWrapCount: 3,
      brownRotationIsThreePinkRotations: true,
    },
    twistedDoubleKeystone: {
      bucket: LOCAL_AEON_ROW_BUDGET,
      halfCarrier: 11,
      doubleKeystone: 22,
      perfectDoubleCover: PERFECT_LOCAL_DOUBLE_COVER_COORDINATE,
      coverDeficit: DOUBLE_KEYSTONE_COVER_DEFICIT,
      foldSwerve: 17,
      crossingCount: 5,
      leakagePressure: 96,
      flatReferencePressure: 0,
      pressureExceedsFlatReference: true,
    },
    toroidalAxis: {
      coordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
      externalToNaturalStack: true,
      terminal: true,
      closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
      closureStride: INTERFERENCE_CLOSURE_STRIDE,
    },
    packedLensRoleTrace: EXACT_PACKED_LENS_ROLE_TRACE,
    packedLensMassTrace: EXACT_INFORMATION_MASS_TRACE,
    packedLensShapeTrace: EXACT_PACKED_LENS_SHAPE_TRACE,
    centerlineGamutTrace: EXACT_CENTERLINE_GAMUT_TRACE,
    verdict: {
      localResolution: LOCAL_AEON_ROW_BUDGET,
      executionPathShape: 'torus',
      informationContainerShape: 'sphere',
      terminalInterferenceShape: 'singularAxis',
      totalPackedMass: 1560,
      centerlineTrace: EXACT_CENTERLINE_GAMUT_TRACE,
      finiteSelfReferenceShape: 'selfReferenceKnot',
    },
    braidPacket,
    returnsToBase: true,
    theoremIds: GNOSTIC_LENS_GEOMETRY_THEOREM_IDS,
  };
}

/**
 * Handles the gnosis closed Loop Runtime Metadata Checksum workflow.
 */
export function closedLoopRuntimeMetadataChecksum(metadata: {
  readonly closedTrace: readonly number[];
  readonly representativeTrace: readonly number[];
  readonly reconstructedTrace: readonly number[];
  readonly axisCoordinate: number;
  readonly closureCoordinate: number;
  readonly totalMass: number;
  readonly totalLeakage: number;
  readonly pressureWeightedTotal: number;
  readonly bucketRatio: number;
}): number {
  return (
    traceTotal(metadata.closedTrace) +
    traceTotal(metadata.representativeTrace) +
    traceTotal(metadata.reconstructedTrace) +
    metadata.axisCoordinate +
    metadata.closureCoordinate +
    metadata.totalMass +
    metadata.totalLeakage +
    metadata.pressureWeightedTotal +
    metadata.bucketRatio
  );
}

/**
 * Creates the Closed Loop Runtime Metadata Certificate.
 */
export function createClosedLoopRuntimeMetadataCertificate(
  gnosticLens: GnosticLensGeometryCertificate | null = createGnosticLensGeometryCertificate(),
  pressureWeightedInterference: PressureWeightedInterferenceStrideCertificate | null = createPressureWeightedInterferenceStrideCertificate(
    gnosticLens === null
      ? null
      : createInterferenceStrideCertificate(gnosticLens.braidPacket)
  )
): ClosedLoopRuntimeMetadataCertificate | null {
  if (
    gnosticLens === null ||
    pressureWeightedInterference === null ||
    !returnsToBase(gnosticLens) ||
    !returnsToBase(pressureWeightedInterference)
  ) {
    return null;
  }

  const braidPacket = gnosticLens.braidPacket;
  const weightedBraidPacket =
    pressureWeightedInterference.interferenceStride.braidPacket;
  const checksumInput = {
    closedTrace: EXACT_CLOSED_LOOP_TRACE,
    representativeTrace: EXACT_CYCLIC_COMPILER_REPRESENTATIVE_TRACE,
    reconstructedTrace: EXACT_CYCLIC_COMPILER_RECONSTRUCTED_TRACE,
    axisCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    totalMass: braidPacket.totalInformationMass,
    totalLeakage: braidPacket.totalLeakage,
    pressureWeightedTotal: pressureWeightedInterference.weightedPressureTotal,
    bucketRatio: gnosticLens.packedGeometryBucketWeight,
  };
  const checksum = closedLoopRuntimeMetadataChecksum(checksumInput);

  if (
    braidPacket.cycle !== weightedBraidPacket.cycle ||
    !sameNumberTrace(
      gnosticLens.centerlineGamutTrace,
      EXACT_CENTERLINE_GAMUT_TRACE
    ) ||
    !sameNumberTrace(
      pressureWeightedInterference.interferenceStride.naturalCoordinates,
      NATURAL_PORT_COORDINATES
    ) ||
    pressureWeightedInterference.anchorCoordinate !==
      GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    pressureWeightedInterference.closureCoordinate !==
      GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE ||
    gnosticLens.toroidalAxis.coordinate !==
      GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    gnosticLens.toroidalAxis.closureCoordinate !==
      GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE ||
    gnosticLens.toroidalAxis.closureStride !== INTERFERENCE_CLOSURE_STRIDE ||
    braidPacket.totalInformationMass !== 1560 ||
    braidPacket.totalLeakage !== 96 ||
    pressureWeightedInterference.weightedPressureTotal !==
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL ||
    gnosticLens.packedGeometryBucketWeight !==
      EXACT_PACKED_GEOMETRY_BUCKET_WEIGHT ||
    checksum !== EXACT_CLOSED_LOOP_RUNTIME_METADATA_CHECKSUM
  ) {
    return null;
  }

  return {
    source: 'GnosisClosedLoopRuntimeMetadataCertificate',
    cycle: braidPacket.cycle,
    closedTrace: EXACT_CLOSED_LOOP_TRACE,
    centerlineTrace: EXACT_CENTERLINE_GAMUT_TRACE,
    representativeTrace: EXACT_CYCLIC_COMPILER_REPRESENTATIVE_TRACE,
    reconstructedTrace: EXACT_CYCLIC_COMPILER_RECONSTRUCTED_TRACE,
    axisCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    totalMass: 1560,
    totalLeakage: 96,
    pressureWeightedTotal: EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL,
    bucketRatio: EXACT_PACKED_GEOMETRY_BUCKET_WEIGHT,
    checksum: EXACT_CLOSED_LOOP_RUNTIME_METADATA_CHECKSUM,
    gnosticLens,
    pressureWeightedInterference,
    returnsToBase: true,
    theoremIds: CLOSED_LOOP_RUNTIME_METADATA_THEOREM_IDS,
  };
}

/**
 * Creates the Pressure Weighted Closed Loop Benchmark Report Certificate.
 */
export function createPressureWeightedClosedLoopBenchmarkReportCertificate(
  closedLoopRuntimeMetadata: ClosedLoopRuntimeMetadataCertificate | null = createClosedLoopRuntimeMetadataCertificate()
): PressureWeightedClosedLoopBenchmarkReportCertificate | null {
  if (
    closedLoopRuntimeMetadata === null ||
    !returnsToBase(closedLoopRuntimeMetadata)
  ) {
    return null;
  }

  const pressureWeightedInterference =
    closedLoopRuntimeMetadata.pressureWeightedInterference;
  if (
    !returnsToBase(pressureWeightedInterference) ||
    !sameNumberTrace(EXACT_CENTERLINE_GAMUT_TRACE, [10, 12, 17, 22, 43]) ||
    !sameNumberTrace(NATURAL_PORT_COORDINATES, [10, 12, 17, 22]) ||
    !sameNumberTrace(EXACT_DECOMPOSITION_TRIPLE_COORDINATES, [7, 17, 22]) ||
    !sameNumberTrace(
      pressureWeightedInterference.strideTrace,
      EXACT_INTERFERENCE_STRIDE_TRACE
    ) ||
    !sameNumberTrace(
      pressureWeightedInterference.leakageTrace,
      EXACT_LEAKAGE_TRACE
    ) ||
    !sameNumberTrace(
      pressureWeightedInterference.weightedPressureTrace,
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_STRIDE_TRACE
    ) ||
    pressureWeightedInterference.weightedPressureTotal !==
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL ||
    pressureWeightedInterference.pressureUnit !== SIEVE_PASCAL_UNIT ||
    closedLoopRuntimeMetadata.pressureWeightedTotal !==
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL
  ) {
    return null;
  }

  return {
    source: 'GnosisPressureWeightedClosedLoopBenchmarkReportCertificate',
    topologyCoordinates: EXACT_CENTERLINE_GAMUT_TRACE,
    gateCoordinates: NATURAL_PORT_COORDINATES,
    decompositionCoordinates: EXACT_DECOMPOSITION_TRIPLE_COORDINATES,
    primeDoubleCrossingCount: 5,
    interferePortCoordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
    interfereClosureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
    interferenceStrideTrace: EXACT_INTERFERENCE_STRIDE_TRACE,
    leakagePressureTrace: EXACT_LEAKAGE_TRACE,
    pressureWeightedInterferenceStrideTrace:
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_STRIDE_TRACE,
    pressureWeightedInterferenceTotal:
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL,
    pressureUnit: SIEVE_PASCAL_UNIT,
    representativeWorkloadTheoremIds: [
      'GamutBraid.exact_closed_loop_weight_accumulation_representative_shortcut',
      'GamutBraid.exact_closed_loop_repeated_unit_workload_certified',
      'GamutBraid.exact_pressure_weighted_closed_loop_workload_certified',
    ],
    closedLoopRuntimeMetadata,
    pressureWeightedInterference,
    returnsToBase: true,
    theoremIds: PRESSURE_WEIGHTED_CLOSED_LOOP_BENCHMARK_REPORT_THEOREM_IDS,
  };
}

export interface CreatePressureCertifiedExecutionPathCertificateInput {
  readonly interferePort?: GnosisUringInterferePortCertificate | null;
  readonly closureFamilyAudit?: IndexedInterferePortClosureFamilyAuditCertificate | null;
  readonly pressureWeightedInterference?: PressureWeightedInterferenceStrideCertificate | null;
  readonly metrology?: GnosticMetrologyProfile | null;
  readonly pressureWeightedClosedLoopBenchmarkReport?: PressureWeightedClosedLoopBenchmarkReportCertificate | null;
}

/**
 * Creates the Pressure Certified Execution Path Certificate.
 */
export function createPressureCertifiedExecutionPathCertificate({
  interferePort = createGnosisUringInterferePortCertificate(),
  closureFamilyAudit,
  pressureWeightedInterference = createPressureWeightedInterferenceStrideCertificate(),
  metrology = createGnosticMetrologyProfile(),
  pressureWeightedClosedLoopBenchmarkReport = createPressureWeightedClosedLoopBenchmarkReportCertificate(),
}: CreatePressureCertifiedExecutionPathCertificateInput = {}): PressureCertifiedExecutionPathCertificate | null {
  const resolvedClosureFamilyAudit =
    closureFamilyAudit ?? interferePort?.closureFamilyAudit ?? null;

  if (
    interferePort === null ||
    resolvedClosureFamilyAudit === null ||
    pressureWeightedInterference === null ||
    metrology === null ||
    pressureWeightedClosedLoopBenchmarkReport === null ||
    !returnsToBase(interferePort) ||
    !returnsToBase(resolvedClosureFamilyAudit) ||
    !returnsToBase(pressureWeightedInterference) ||
    !returnsToBase(metrology) ||
    !returnsToBase(pressureWeightedClosedLoopBenchmarkReport)
  ) {
    return null;
  }

  const pressureWeighted =
    pressureWeightedClosedLoopBenchmarkReport.pressureWeightedInterference;
  if (
    !sameNumberTrace(
      pressureWeightedClosedLoopBenchmarkReport.topologyCoordinates,
      EXACT_CENTERLINE_GAMUT_TRACE
    ) ||
    !sameNumberTrace(
      pressureWeightedClosedLoopBenchmarkReport.gateCoordinates,
      NATURAL_PORT_COORDINATES
    ) ||
    !sameNumberTrace(
      pressureWeightedClosedLoopBenchmarkReport.decompositionCoordinates,
      EXACT_DECOMPOSITION_TRIPLE_COORDINATES
    ) ||
    pressureWeightedClosedLoopBenchmarkReport.primeDoubleCrossingCount !== 5 ||
    pressureWeightedClosedLoopBenchmarkReport.interferePortCoordinate !==
      GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    pressureWeightedClosedLoopBenchmarkReport.interfereClosureCoordinate !==
      GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE ||
    pressureWeightedClosedLoopBenchmarkReport.pressureWeightedInterferenceTotal !==
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL ||
    pressureWeightedClosedLoopBenchmarkReport.pressureUnit !==
      SIEVE_PASCAL_UNIT ||
    !sameStringTrace(
      pressureWeightedClosedLoopBenchmarkReport.theoremIds,
      PRESSURE_WEIGHTED_CLOSED_LOOP_BENCHMARK_REPORT_THEOREM_IDS
    ) ||
    interferePort.portAction !== 'interfere' ||
    interferePort.portCoordinate !== GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    interferePort.closureCoordinate !==
      GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE ||
    !interferePort.terminal ||
    resolvedClosureFamilyAudit.portCoordinate !==
      GNOSIS_URING_INTERFERE_PORT_COORDINATE ||
    resolvedClosureFamilyAudit.closureFamilyPressureTotal !==
      GNOSIS_URING_BOUNDED_CLOSURE_FAMILY_PRESSURE_TOTAL ||
    resolvedClosureFamilyAudit.pressureUnit !== SIEVE_PASCAL_UNIT ||
    !sameNumberTrace(
      resolvedClosureFamilyAudit.closureIndices,
      BOUNDED_INTERFERENCE_CLOSURE_FAMILY_INDICES
    ) ||
    !sameNumberTrace(
      pressureWeightedInterference.strideTrace,
      EXACT_INTERFERENCE_STRIDE_TRACE
    ) ||
    !sameNumberTrace(
      pressureWeightedInterference.leakageTrace,
      EXACT_LEAKAGE_TRACE
    ) ||
    !sameNumberTrace(
      pressureWeightedInterference.weightedPressureTrace,
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_STRIDE_TRACE
    ) ||
    pressureWeightedInterference.weightedPressureTotal !==
      EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL ||
    pressureWeightedInterference.pressureUnit !== SIEVE_PASCAL_UNIT ||
    pressureWeighted.weightedPressureTotal !==
      pressureWeightedInterference.weightedPressureTotal ||
    metrology.totalGnosticMass !== 1560 ||
    metrology.totalSievePressure !== 96 ||
    metrology.massUnit !== GNOSTIC_GRAM_UNIT ||
    metrology.pressureUnit !== SIEVE_PASCAL_UNIT
  ) {
    return null;
  }

  return {
    source: 'GnosisPressureCertifiedExecutionPathCertificate',
    certificateVersion: PRESSURE_CERTIFIED_EXECUTION_PATH_VERSION,
    pressureIdentity: PRESSURE_CERTIFIED_EXECUTION_PATH_IDENTITY,
    runtime: 'gnosis',
    host: 'gnosis-uring',
    topologyCoordinates: EXACT_CENTERLINE_GAMUT_TRACE,
    gateCoordinates: NATURAL_PORT_COORDINATES,
    decompositionCoordinates: EXACT_DECOMPOSITION_TRIPLE_COORDINATES,
    primeDoubleCrossingCount: 5,
    interferePort: {
      action: 'interfere',
      coordinate: GNOSIS_URING_INTERFERE_PORT_COORDINATE,
      closureCoordinate: GNOSIS_URING_INTERFERE_CLOSURE_COORDINATE,
      terminal: true,
    },
    pressureWeightedInterference: {
      strideTrace: EXACT_INTERFERENCE_STRIDE_TRACE,
      leakagePressureTrace: EXACT_LEAKAGE_TRACE,
      pressureWeightedStrideTrace:
        EXACT_PRESSURE_WEIGHTED_INTERFERENCE_STRIDE_TRACE,
      pressureWeightedTotal: EXACT_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL,
      pressureUnit: SIEVE_PASCAL_UNIT,
    },
    closureFamilyAudit: resolvedClosureFamilyAudit,
    informationMassTotal: 1560,
    leakageTotal: 96,
    metrology: {
      informationMassTotal: 1560,
      leakageTotal: 96,
      massUnit: GNOSTIC_GRAM_UNIT,
      pressureUnit: SIEVE_PASCAL_UNIT,
    },
    pressureWeightedClosedLoopBenchmarkReport,
    returnsToBase: true,
    theoremIds: PRESSURE_CERTIFIED_EXECUTION_PATH_THEOREM_IDS,
  };
}

export interface CreateWankelRuntimeCertificateInput {
  readonly closedLoopRuntimeMetadata?: ClosedLoopRuntimeMetadataCertificate | null;
  readonly pressureWeightedClosedLoopBenchmarkReport?: PressureWeightedClosedLoopBenchmarkReportCertificate | null;
  readonly pressureCertifiedExecutionPath?: PressureCertifiedExecutionPathCertificate | null;
}

/**
 * Creates the Wankel Runtime Certificate.
 */
export function createWankelRuntimeCertificate({
  closedLoopRuntimeMetadata = createClosedLoopRuntimeMetadataCertificate(),
  pressureWeightedClosedLoopBenchmarkReport = createPressureWeightedClosedLoopBenchmarkReportCertificate(
    closedLoopRuntimeMetadata
  ),
  pressureCertifiedExecutionPath = createPressureCertifiedExecutionPathCertificate(
    { pressureWeightedClosedLoopBenchmarkReport }
  ),
}: CreateWankelRuntimeCertificateInput = {}): WankelRuntimeCertificate | null {
  if (
    closedLoopRuntimeMetadata === null ||
    pressureWeightedClosedLoopBenchmarkReport === null ||
    pressureCertifiedExecutionPath === null ||
    !returnsToBase(closedLoopRuntimeMetadata) ||
    !returnsToBase(pressureWeightedClosedLoopBenchmarkReport) ||
    !returnsToBase(pressureCertifiedExecutionPath)
  ) {
    return null;
  }

  if (
    pressureWeightedClosedLoopBenchmarkReport.closedLoopRuntimeMetadata !==
      closedLoopRuntimeMetadata ||
    pressureCertifiedExecutionPath.pressureWeightedClosedLoopBenchmarkReport !==
      pressureWeightedClosedLoopBenchmarkReport ||
    pressureCertifiedExecutionPath.runtime !== 'gnosis' ||
    pressureCertifiedExecutionPath.host !== 'gnosis-uring' ||
    !sameNumberTrace(
      pressureWeightedClosedLoopBenchmarkReport.topologyCoordinates,
      EXACT_CENTERLINE_GAMUT_TRACE
    ) ||
    !sameStringTrace(
      WANKEL_FIVE_FORCE_LIFECYCLE_TRACE,
      ['fork', 'race', 'fold', 'vent', 'interfere']
    ) ||
    WANKEL_AEON_CELLS !== 12 ||
    WANKEL_RUNTIME_DEADLINE_PULSE_HOPS !== 264
  ) {
    return null;
  }

  return {
    source: 'GnosisWankelRuntimeCertificate',
    runtime: 'gnosis',
    host: 'gnosis-uring',
    aeonCells: WANKEL_AEON_CELLS,
    lifecycleTrace: WANKEL_FIVE_FORCE_LIFECYCLE_TRACE,
    deadlinePulseHops: WANKEL_RUNTIME_DEADLINE_PULSE_HOPS,
    closedLoopRuntimeMetadata,
    pressureWeightedClosedLoopBenchmarkReport,
    pressureCertifiedExecutionPath,
    returnsToBase: true,
    theoremIds: WANKEL_RUNTIME_CERTIFICATE_THEOREM_IDS,
  };
}

/**
 * Creates the Gnostic Metrology Profile.
 */
export function createGnosticMetrologyProfile(
  certificate: StatisticalMechanicsAccountingCertificate | null = createStatisticalMechanicsAccounting()
): GnosticMetrologyProfile | null {
  if (certificate === null || !returnsToBase(certificate)) {
    return null;
  }

  const virtualMass =
    certificate.totalInformationMass - LOCAL_AEON_CARRYING_CAPACITY;
  if (virtualMass !== 1416) {
    return null;
  }

  return {
    source: 'GnosisGnosticMetrologyProfile',
    massUnit: GNOSTIC_GRAM_UNIT,
    pressureUnit: SIEVE_PASCAL_UNIT,
    localCarryingCapacity: LOCAL_AEON_CARRYING_CAPACITY,
    virtualMass,
    totalGnosticMass: certificate.totalInformationMass,
    totalSievePressure: certificate.totalLeakage,
    checksumMass: certificate.totalInformationMass,
    shootGamutPressureRequirement: certificate.totalLeakage,
    brownBufferMass: certificate.informationMassTrace[2],
    brownLeakageMass: certificate.leakageMassTrace[2],
    layerRows: [
      {
        band: EXACT_NOISE_BANDS[0],
        saturation: certificate.saturationTrace[0],
        visibleMass: certificate.visibleMassTrace[0],
        sievePressure: certificate.leakageTrace[0],
        gnosticMass: certificate.informationMassTrace[0],
        leakageMass: certificate.leakageMassTrace[0],
      },
      {
        band: EXACT_NOISE_BANDS[1],
        saturation: certificate.saturationTrace[1],
        visibleMass: certificate.visibleMassTrace[1],
        sievePressure: certificate.leakageTrace[1],
        gnosticMass: certificate.informationMassTrace[1],
        leakageMass: certificate.leakageMassTrace[1],
      },
      {
        band: EXACT_NOISE_BANDS[2],
        saturation: certificate.saturationTrace[2],
        visibleMass: certificate.visibleMassTrace[2],
        sievePressure: certificate.leakageTrace[2],
        gnosticMass: certificate.informationMassTrace[2],
        leakageMass: certificate.leakageMassTrace[2],
      },
    ],
    returnsToBase: true,
    theoremIds: certificate.theoremIds,
  };
}

/**
 * Creates the Pressure Gradient Certificate.
 */
export function createPressureGradientCertificate(
  profile: GnosticMetrologyProfile | null = createGnosticMetrologyProfile()
): PressureGradientCertificate | null {
  if (profile === null || !returnsToBase(profile)) {
    return null;
  }

  if (
    profile.totalSievePressure !== 96 ||
    PRESSURE_GRADIENT_MULTIPLIER * LOCAL_AEON_ROW_BUDGET !== 96
  ) {
    return null;
  }

  return {
    source: 'GnosisPressureGradientCertificate',
    bucketSize: LOCAL_AEON_ROW_BUDGET,
    bucketCount: PRESSURE_GRADIENT_MULTIPLIER,
    totalSievePressure: profile.totalSievePressure,
    bucketProduct: 96,
    reserveSievePressure: profile.totalSievePressure,
    returnsToBase: true,
    theoremIds: profile.theoremIds,
  };
}

/**
 * Creates the Gnostic Runtime Allocation Plan.
 */
export function createGnosticRuntimeAllocationPlan(
  observedMass: number,
  profile: GnosticMetrologyProfile | null = createGnosticMetrologyProfile()
): GnosticRuntimeAllocationPlan | null {
  if (profile === null) {
    return null;
  }
  const pressureGradient = createPressureGradientCertificate(profile);
  if (pressureGradient === null) {
    return null;
  }

  const checksumMatches =
    Number.isFinite(observedMass) && observedMass === profile.checksumMass;

  return {
    source: 'GnosisRuntimeAllocationPlan',
    observedMass,
    expectedMass: profile.checksumMass,
    checksumMatches,
    reserveBrownBufferMass: profile.brownBufferMass,
    reserveSievePressure: pressureGradient.reserveSievePressure,
    pressureGradient,
    admitted: checksumMatches,
    reason: checksumMatches ? 'checksum-match' : 'checksum-mismatch',
    theoremIds: profile.theoremIds,
  };
}

/**
 * Creates the Calibrated Fluidic Pressure Bridge.
 */
export function createCalibratedFluidicPressureBridge(
  calibrationPaPerSPa: number,
  profile: GnosticMetrologyProfile | null = createGnosticMetrologyProfile()
): CalibratedFluidicPressureBridge | null {
  if (!Number.isFinite(calibrationPaPerSPa) || calibrationPaPerSPa <= 0) {
    return null;
  }
  if (profile === null) {
    return null;
  }
  const pressureGradient = createPressureGradientCertificate(profile);
  if (pressureGradient === null) {
    return null;
  }

  const pressureTracePa: readonly [number, number, number] = [
    profile.layerRows[0].sievePressure * calibrationPaPerSPa,
    profile.layerRows[1].sievePressure * calibrationPaPerSPa,
    profile.layerRows[2].sievePressure * calibrationPaPerSPa,
  ];

  return {
    source: 'GnosisCalibratedFluidicPressureBridge',
    calibrationPaPerSPa,
    pressureTracePa,
    totalPhysicalPressurePa: profile.totalSievePressure * calibrationPaPerSPa,
    pinkPhysicalPressurePa: pressureTracePa[1],
    brownPhysicalPressurePa: pressureTracePa[2],
    pressureGradient,
    admitted: true,
    reason: 'calibrated-pressure-bridge',
    theoremIds: profile.theoremIds,
  };
}

/**
 * Creates the Fluidic Routing Admissibility Certificate.
 */
export function createFluidicRoutingAdmissibilityCertificate(
  calibrationPaPerSPa: number,
  observedMass: number,
  profile: GnosticMetrologyProfile | null = createGnosticMetrologyProfile()
): FluidicRoutingAdmissibilityCertificate | null {
  const allocationPlan = createGnosticRuntimeAllocationPlan(
    observedMass,
    profile
  );
  if (allocationPlan === null || !allocationPlan.admitted) {
    return null;
  }

  const fluidicBridge = createCalibratedFluidicPressureBridge(
    calibrationPaPerSPa,
    profile
  );
  if (fluidicBridge === null) {
    return null;
  }

  const preservesGradient =
    fluidicBridge.totalPhysicalPressurePa ===
    calibrationPaPerSPa * allocationPlan.pressureGradient.bucketProduct;
  const pressureRankPreserved =
    fluidicBridge.brownPhysicalPressurePa >=
    fluidicBridge.pinkPhysicalPressurePa;
  if (!preservesGradient || !pressureRankPreserved) {
    return null;
  }

  return {
    source: 'GnosisFluidicRoutingAdmissibilityCertificate',
    calibrationPaPerSPa,
    observedMass,
    expectedMass: allocationPlan.expectedMass,
    checksumMatches: true,
    pressureRankedBands: EXACT_PRESSURE_RANKED_BANDS,
    dominantBand: 'brown',
    dominantSievePressure: 78,
    dominantPhysicalPressurePa: fluidicBridge.brownPhysicalPressurePa,
    pinkPhysicalPressurePa: fluidicBridge.pinkPhysicalPressurePa,
    totalPhysicalPressurePa: fluidicBridge.totalPhysicalPressurePa,
    preservesGradient: true,
    allocationPlan,
    fluidicBridge,
    pressureGradient: allocationPlan.pressureGradient,
    admitted: true,
    returnsToBase: true,
    reason: 'positive-calibration-checksum-match',
    theoremIds: allocationPlan.theoremIds,
  };
}

/**
 * Handles the gnosis read Braid Fold Candidate workflow.
 */
export function readBraidFoldCandidate(
  value: unknown
): BraidFoldCandidate | null {
  if (typeof value !== 'object' || value === null) {
    return null;
  }
  const record = value as Record<string, unknown>;
  const cycle = record.cycle;
  const gateCoordinates = record.gateCoordinates;
  const saturationTrace = record.saturationTrace;
  const closedArchitecture = record.closedArchitecture;
  const endpointsLinked = record.endpointsLinked;
  const baseReady = record.baseReady;

  if (
    typeof cycle !== 'number' ||
    !isNonNegativeInteger(cycle) ||
    !Array.isArray(gateCoordinates) ||
    !Array.isArray(saturationTrace) ||
    typeof closedArchitecture !== 'boolean' ||
    typeof endpointsLinked !== 'boolean' ||
    typeof baseReady !== 'boolean'
  ) {
    return null;
  }
  if (
    !gateCoordinates.every(
      (coordinate): coordinate is number =>
        typeof coordinate === 'number' && isNonNegativeInteger(coordinate)
    ) ||
    !saturationTrace.every(
      (saturation): saturation is number =>
        typeof saturation === 'number' && isNonNegativeInteger(saturation)
    )
  ) {
    return null;
  }

  return {
    cycle,
    gateCoordinates,
    saturationTrace,
    closedArchitecture,
    endpointsLinked,
    baseReady,
  };
}

/**
 * Handles the gnosis read Decomposition Triple Candidate workflow.
 */
export function readDecompositionTripleCandidate(
  value: unknown
): DecompositionTripleCandidate | null {
  if (typeof value !== 'object' || value === null) {
    return null;
  }
  const record = value as Record<string, unknown>;
  const cycle = record.cycle;
  const rawCoordinates = record.coordinates ?? record.decompositionCoordinates;

  if (
    typeof cycle !== 'number' ||
    !isNonNegativeInteger(cycle) ||
    !Array.isArray(rawCoordinates)
  ) {
    return null;
  }
  if (
    !rawCoordinates.every(
      (coordinate): coordinate is number =>
        typeof coordinate === 'number' && isNonNegativeInteger(coordinate)
    )
  ) {
    return null;
  }

  return {
    cycle,
    coordinates: rawCoordinates,
  };
}

/**
 * Handles the gnosis audit Braid Fold Candidate workflow.
 */
export function auditBraidFoldCandidate(
  candidate: BraidFoldCandidate
): BraidFoldAudit {
  const anchorCoordinates = anchorCoordinatesFromTrace(
    candidate.gateCoordinates
  );

  if (!sameNumberTrace(candidate.gateCoordinates, EXACT_LAYER_COORDINATES)) {
    return {
      accepted: false,
      verdict: Verdict.Decline,
      reason: 'gate coordinates must be exactly 10,12,17,22',
      anchorCoordinates,
      certificate: null,
    };
  }
  if (!sameNumberTrace(candidate.saturationTrace, EXACT_SATURATION_TRACE)) {
    return {
      accepted: false,
      verdict: Verdict.Decline,
      reason: 'saturation trace must be exactly 10,30,90',
      anchorCoordinates,
      certificate: null,
    };
  }
  // The candidate is the right canonical shape (gates + saturation match) but
  // its readiness flags are not yet asserted: deliberate deferral, not a hard
  // rejection — it can be re-audited once the flags are supplied.
  if (!candidate.closedArchitecture) {
    return {
      accepted: false,
      verdict: Verdict.Abstain,
      reason: 'closed architecture certificate is absent',
      anchorCoordinates,
      certificate: null,
    };
  }
  if (!candidate.endpointsLinked) {
    return {
      accepted: false,
      verdict: Verdict.Abstain,
      reason: 'braid endpoints are not linked',
      anchorCoordinates,
      certificate: null,
    };
  }
  if (!candidate.baseReady) {
    return {
      accepted: false,
      verdict: Verdict.Abstain,
      reason: 'braid pass does not return to base readiness',
      anchorCoordinates,
      certificate: null,
    };
  }
  if (keystoneGap(17, 22) !== 5) {
    return {
      accepted: false,
      verdict: Verdict.Decline,
      reason: 'prime-to-double crossing count is not five',
      anchorCoordinates,
      certificate: null,
    };
  }

  return {
    accepted: true,
    verdict: Verdict.Accept,
    reason: 'exact braid fold certificate accepted',
    anchorCoordinates,
    certificate: {
      source: 'GnosisBraidFoldCertificate',
      cycle: candidate.cycle,
      layerCoordinates: EXACT_LAYER_COORDINATES,
      saturationTrace: EXACT_SATURATION_TRACE,
      forkedAnchorCoordinates: BRAID_FOLD_ANCHOR_COORDINATES,
      primeDoubleCrossingCount: 5,
      closedArchitecture: true,
      endpointsLinked: true,
      baseReady: true,
      returnsToBase: true,
      theoremIds: BRAID_FOLD_THEOREM_IDS,
    },
  };
}

/**
 * Creates the Braid Fold Certificate.
 */
export function createBraidFoldCertificate(
  candidate: BraidFoldCandidate
): BraidFoldCertificate | null {
  return auditBraidFoldCandidate(candidate).certificate;
}

/**
 * Handles the gnosis audit Decomposition Triple Candidate workflow.
 */
export function auditDecompositionTripleCandidate(
  candidate: DecompositionTripleCandidate,
  braidFoldCertificate: BraidFoldCertificate | null
): DecompositionTripleAudit {
  if (
    !sameNumberTrace(
      candidate.coordinates,
      EXACT_DECOMPOSITION_TRIPLE_COORDINATES
    )
  ) {
    return {
      accepted: false,
      reason: 'decomposition coordinates must be exactly 7,17,22',
      coordinates: candidate.coordinates,
      certificate: null,
    };
  }
  if (braidFoldCertificate === null) {
    return {
      accepted: false,
      reason: 'braid fold certificate is absent',
      coordinates: candidate.coordinates,
      certificate: null,
    };
  }
  if (candidate.cycle !== braidFoldCertificate.cycle) {
    return {
      accepted: false,
      reason: 'decomposition cycle must match braid fold cycle',
      coordinates: candidate.coordinates,
      certificate: null,
    };
  }

  const triple = createExactDecompositionTriple();
  if (!decompositionFeedsKenomaSpan(triple)) {
    return {
      accepted: false,
      reason: 'decomposition gate does not feed prime anchor by kenoma span',
      coordinates: candidate.coordinates,
      certificate: null,
    };
  }
  if (!decompositionAnchorsKeystones(triple, braidFoldCertificate)) {
    return {
      accepted: false,
      reason: 'decomposition anchors do not match prime and double keystones',
      coordinates: candidate.coordinates,
      certificate: null,
    };
  }
  if (
    triple.foldAnchor !==
    triple.raceAnchor + braidFoldCertificate.primeDoubleCrossingCount
  ) {
    return {
      accepted: false,
      reason: 'decomposition fold does not match prime-double crossing count',
      coordinates: candidate.coordinates,
      certificate: null,
    };
  }
  if (!returnsToBase(braidFoldCertificate)) {
    return {
      accepted: false,
      reason: 'braid fold certificate does not return to base',
      coordinates: candidate.coordinates,
      certificate: null,
    };
  }

  return {
    accepted: true,
    reason: 'exact 7,17,22 decomposition certificate accepted',
    coordinates: EXACT_DECOMPOSITION_TRIPLE_COORDINATES,
    certificate: {
      source: 'GnosisDecompositionTripleCertificate',
      cycle: candidate.cycle,
      coordinates: EXACT_DECOMPOSITION_TRIPLE_COORDINATES,
      triple: {
        decompositionGate: 7,
        raceAnchor: 17,
        foldAnchor: 22,
      },
      decompositionFeedsKenomaSpan: true,
      anchorsKeystones: true,
      primeDoubleCrossingCount: 5,
      braidFoldCertificate,
      returnsToBase: true,
      theoremIds: DECOMPOSITION_TRIPLE_THEOREM_IDS,
    },
  };
}

/**
 * Creates the Decomposition Triple Certificate.
 */
export function createDecompositionTripleCertificate(
  candidate: DecompositionTripleCandidate,
  braidFoldCertificate: BraidFoldCertificate | null
): DecompositionTripleCertificate | null {
  return auditDecompositionTripleCandidate(candidate, braidFoldCertificate)
    .certificate;
}

/**
 * Handles the gnosis select Certified Braid Fast Path workflow.
 */
export function selectCertifiedBraidFastPath(
  certificate: BraidFoldCertificate | null
): CertifiedBraidFastPathDecision {
  if (certificate === null) {
    return {
      selected: false,
      verdict: Verdict.Decline,
      reason: 'braid fold certificate is absent',
      path: null,
    };
  }
  if (!returnsToBase(certificate)) {
    // A present certificate that we deliberately do not adopt because the
    // base-return gate is unmet: deferred non-adoption, not a hard rejection.
    return {
      selected: false,
      verdict: Verdict.Abstain,
      reason: 'braid fold certificate does not return to base',
      path: null,
    };
  }

  return {
    selected: true,
    verdict: Verdict.Accept,
    reason: 'certified braid fast path selected',
    path: {
      source: 'GnosisCertifiedBraidFastPath',
      certificate,
      forkedAnchorCoordinates: BRAID_FOLD_ANCHOR_COORDINATES,
      collapsedBridge: {
        from: 17,
        to: 22,
        stride: 5,
      },
      returnsToBase: true,
    },
  };
}

export function certifyBraidFastPathEquivalence<T>(
  certificate: BraidFoldCertificate | null,
  linearResult: T,
  certifiedResult: T,
  equivalent: (linearResult: T, certifiedResult: T) => boolean = Object.is
): CertifiedBraidFastPathEquivalence<T> {
  const decision = selectCertifiedBraidFastPath(certificate);
  return {
    decision,
    equivalent: decision.selected && equivalent(linearResult, certifiedResult),
    linearResult,
    certifiedResult,
  };
}

function isExactWankelRuntimeCertificate(
  certificate: WankelRuntimeCertificate
): boolean {
  return (
    certificate.source === 'GnosisWankelRuntimeCertificate' &&
    certificate.runtime === 'gnosis' &&
    certificate.host === 'gnosis-uring' &&
    certificate.aeonCells === WANKEL_AEON_CELLS &&
    certificate.deadlinePulseHops === WANKEL_RUNTIME_DEADLINE_PULSE_HOPS &&
    sameStringTrace(
      certificate.lifecycleTrace,
      WANKEL_FIVE_FORCE_LIFECYCLE_TRACE
    ) &&
    certificate.pressureWeightedClosedLoopBenchmarkReport
      .closedLoopRuntimeMetadata === certificate.closedLoopRuntimeMetadata &&
    certificate.pressureCertifiedExecutionPath
      .pressureWeightedClosedLoopBenchmarkReport ===
      certificate.pressureWeightedClosedLoopBenchmarkReport &&
    returnsToBase(certificate.closedLoopRuntimeMetadata) &&
    returnsToBase(certificate.pressureWeightedClosedLoopBenchmarkReport) &&
    returnsToBase(certificate.pressureCertifiedExecutionPath) &&
    sameStringTrace(
      certificate.theoremIds,
      WANKEL_RUNTIME_CERTIFICATE_THEOREM_IDS
    )
  );
}

/**
 * Handles the gnosis select Wankel Runtime Fast Path workflow.
 */
export function selectWankelRuntimeFastPath(
  certificate: WankelRuntimeCertificate | null
): WankelRuntimeFastPathDecision {
  if (certificate === null) {
    return {
      selected: false,
      verdict: Verdict.Decline,
      reason: 'wankel runtime certificate is absent',
      certificate: null,
      deadlinePulseHops: null,
      lifecycleTrace: null,
    };
  }
  if (!returnsToBase(certificate)) {
    // A present certificate deliberately not adopted because the base-return
    // gate is unmet: deferred non-adoption, not a malformed candidate.
    return {
      selected: false,
      verdict: Verdict.Abstain,
      reason: 'wankel runtime certificate does not return to base',
      certificate: null,
      deadlinePulseHops: null,
      lifecycleTrace: null,
    };
  }
  if (!isExactWankelRuntimeCertificate(certificate)) {
    // Wrong shape: an inexact certificate can never be the Wankel fast path —
    // a hard rejection of a malformed candidate.
    return {
      selected: false,
      verdict: Verdict.Decline,
      reason: 'wankel runtime certificate is inexact',
      certificate: null,
      deadlinePulseHops: null,
      lifecycleTrace: null,
    };
  }

  return {
    selected: true,
    verdict: Verdict.Accept,
    reason: 'wankel runtime fast path selected',
    certificate,
    deadlinePulseHops: WANKEL_RUNTIME_DEADLINE_PULSE_HOPS,
    lifecycleTrace: WANKEL_FIVE_FORCE_LIFECYCLE_TRACE,
  };
}

export function certifyWankelRuntimeFastPathEquivalence<T>(
  certificate: WankelRuntimeCertificate | null,
  linearResult: T,
  certifiedResult: T,
  equivalent: (linearResult: T, certifiedResult: T) => boolean = Object.is
): WankelRuntimeFastPathEquivalence<T> {
  const decision = selectWankelRuntimeFastPath(certificate);
  return {
    decision,
    equivalent: decision.selected && equivalent(linearResult, certifiedResult),
    linearResult,
    certifiedResult,
  };
}

export function certifyWankelRuntimeFastPathCostDominance<T>(
  certificate: WankelRuntimeCertificate | null,
  linearResult: T,
  certifiedResult: T,
  witness: WankelRuntimeFastPathCostWitness,
  equivalent: (linearResult: T, certifiedResult: T) => boolean = Object.is
): WankelRuntimeFastPathCostDominance<T> {
  const equivalence = certifyWankelRuntimeFastPathEquivalence(
    certificate,
    linearResult,
    certifiedResult,
    equivalent
  );
  const finitePositiveCosts =
    Number.isFinite(witness.selectedCost) &&
    Number.isFinite(witness.baselineCost) &&
    witness.selectedCost > 0 &&
    witness.baselineCost > 0;
  const dominates =
    equivalence.equivalent &&
    finitePositiveCosts &&
    witness.selectedCost < witness.baselineCost;

  return {
    equivalence,
    witness,
    dominates,
    reason: !equivalence.decision.selected
      ? equivalence.decision.reason
      : !equivalence.equivalent
        ? 'wankel runtime fast path result is not equivalent'
        : !finitePositiveCosts
          ? 'wankel runtime cost witness must be positive and finite'
          : dominates
            ? 'wankel runtime fast path cost dominance certified'
            : 'wankel runtime fast path is not faster than baseline',
    theoremId: 'RuntimeCertificate.wankel_fast_path_cost_dominates_baseline',
  };
}

export function certifyWankelRuntimeFastPathAggregateCostDominance<T>(
  certificate: WankelRuntimeCertificate | null,
  linearResult: T,
  certifiedResult: T,
  witness: WankelRuntimeFastPathAggregateCostWitness,
  equivalent: (linearResult: T, certifiedResult: T) => boolean = Object.is
): WankelRuntimeFastPathAggregateCostDominance<T> {
  const equivalence = certifyWankelRuntimeFastPathEquivalence(
    certificate,
    linearResult,
    certifiedResult,
    equivalent
  );
  const validSampleCount =
    Number.isInteger(witness.sampleCount) && witness.sampleCount > 0;
  const finitePositiveCosts =
    Number.isFinite(witness.selectedTotalCost) &&
    Number.isFinite(witness.baselineTotalCost) &&
    witness.selectedTotalCost > 0 &&
    witness.baselineTotalCost > 0;
  const dominates =
    equivalence.equivalent &&
    validSampleCount &&
    finitePositiveCosts &&
    witness.selectedTotalCost < witness.baselineTotalCost;

  return {
    equivalence,
    witness,
    dominates,
    reason: !equivalence.decision.selected
      ? equivalence.decision.reason
      : !equivalence.equivalent
        ? 'wankel runtime fast path result is not equivalent'
        : !validSampleCount
          ? 'wankel runtime aggregate cost witness sample count must be a positive integer'
          : !finitePositiveCosts
            ? 'wankel runtime aggregate costs must be positive and finite'
            : dominates
              ? 'wankel runtime aggregate fast path cost dominance certified'
              : 'wankel runtime aggregate fast path is not faster than baseline',
    theoremId:
      'RuntimeCertificate.wankel_aggregate_fast_path_cost_dominates_baseline',
  };
}

export function certifyWankelRuntimeFastPathRobustEstimatorDominance<T>(
  certificate: WankelRuntimeCertificate | null,
  linearResult: T,
  certifiedResult: T,
  witness: WankelRuntimeFastPathRobustEstimatorWitness,
  equivalent: (linearResult: T, certifiedResult: T) => boolean = Object.is
): WankelRuntimeFastPathRobustEstimatorDominance<T> {
  const equivalence = certifyWankelRuntimeFastPathEquivalence(
    certificate,
    linearResult,
    certifiedResult,
    equivalent
  );
  const validSampleCoverage =
    Number.isInteger(witness.sampleCount) &&
    Number.isInteger(witness.minimumSampleCount) &&
    witness.minimumSampleCount > 0 &&
    witness.sampleCount >= witness.minimumSampleCount;
  const finitePositiveAggregateCosts =
    Number.isFinite(witness.selectedTotalCost) &&
    Number.isFinite(witness.baselineTotalCost) &&
    witness.selectedTotalCost > 0 &&
    witness.baselineTotalCost > 0;
  const finitePositiveRobustCosts =
    Number.isFinite(witness.selectedRobustCost) &&
    Number.isFinite(witness.baselineRobustCost) &&
    witness.selectedRobustCost > 0 &&
    witness.baselineRobustCost > 0;
  const validJitterBudget =
    Number.isFinite(witness.observedJitter) &&
    Number.isFinite(witness.jitterBudget) &&
    witness.observedJitter >= 0 &&
    witness.jitterBudget >= 0 &&
    witness.observedJitter <= witness.jitterBudget;
  const validOutlierBudget =
    Number.isInteger(witness.outlierBudget) &&
    witness.outlierBudget >= 0 &&
    Number.isInteger(witness.sampleCount) &&
    witness.outlierBudget < witness.sampleCount;
  const dominates =
    equivalence.equivalent &&
    validSampleCoverage &&
    finitePositiveAggregateCosts &&
    witness.selectedTotalCost < witness.baselineTotalCost &&
    finitePositiveRobustCosts &&
    witness.selectedRobustCost < witness.baselineRobustCost &&
    validJitterBudget &&
    validOutlierBudget;

  return {
    equivalence,
    witness,
    dominates,
    reason: !equivalence.decision.selected
      ? equivalence.decision.reason
      : !equivalence.equivalent
        ? 'wankel runtime fast path result is not equivalent'
        : !validSampleCoverage
          ? 'wankel runtime robust estimator witness requires minimum sample coverage'
          : !finitePositiveAggregateCosts
            ? 'wankel runtime robust estimator aggregate costs must be positive and finite'
            : witness.selectedTotalCost >= witness.baselineTotalCost
              ? 'wankel runtime robust estimator aggregate fast path is not faster than baseline'
              : !finitePositiveRobustCosts
                ? 'wankel runtime robust estimator costs must be positive and finite'
                : witness.selectedRobustCost >= witness.baselineRobustCost
                  ? 'wankel runtime robust estimator fast path is not faster than baseline'
                  : !validJitterBudget
                    ? 'wankel runtime robust estimator jitter exceeds budget'
                    : !validOutlierBudget
                      ? 'wankel runtime robust estimator outlier budget must be within samples'
                      : 'wankel runtime robust estimator cost dominance certified',
    theoremId:
      'RuntimeCertificate.wankel_robust_fast_path_estimator_dominates_baseline',
  };
}
